import { useEffect, useState, useCallback } from 'react';
import { getApiConfig, saveApiConfig, testApiConfig, getMemberPreview } from '../../api/issuer';
import Button from '../../components/common/Button';
import Input from '../../components/common/Input';
import { CardSkeleton } from '../../components/common/SkeletonLoader';
import toast from 'react-hot-toast';
import {
  CheckCircle2, XCircle, AlertTriangle, Plug, ChevronRight,
  Database, Users, Building2, GraduationCap, Briefcase, Network,
  Key, ShieldCheck, Lock, Server, ArrowRight, Search, Zap,
  RefreshCw, Loader2, Check, Plus, Trash2, ArrowLeft,
} from 'lucide-react';

// ── Helpers ────────────────────────────────────────────────────────────────

const SYSTEM_TYPES = [
  { id: 'rest_api', label: 'REST API', icon: Network, desc: 'Connect any REST API endpoint' },
  { id: 'erp', label: 'ERP System', icon: Building2, desc: 'SAP, Oracle, Microsoft Dynamics' },
  { id: 'sis', label: 'Student Information System', icon: GraduationCap, desc: 'Banner, PeopleSoft, Ellucian' },
  { id: 'hr', label: 'HR System', icon: Users, desc: 'Workday, BambooHR, ADP' },
  { id: 'membership', label: 'Membership System', icon: Briefcase, desc: 'Association or membership platforms' },
  { id: 'custom', label: 'Custom System', icon: Server, desc: 'Any database or internal system' },
];

const AUTH_METHODS = [
  { id: 'api_key', label: 'API Key', icon: Key, desc: 'Static key passed in request header' },
  { id: 'bearer', label: 'Bearer Token', icon: ShieldCheck, desc: 'OAuth 2.0 / JWT Bearer token' },
  { id: 'basic', label: 'Basic Auth', icon: Lock, desc: 'Username and password' },
  { id: 'service_account', label: 'Service Account', icon: Server, desc: 'Service-level credentials' },
];

const SOURCES_BY_TYPE = {
  sis: ['Students', 'Graduates', 'Alumni', 'Researchers', 'Faculty'],
  hr: ['Employees', 'Contractors', 'Interns', 'Partners', 'Consultants'],
  erp: ['Employees', 'Vendors', 'Customers', 'Partners'],
  membership: ['Members', 'Premium Members', 'Alumni', 'Associates'],
  rest_api: ['Records', 'Members', 'Users', 'Entities'],
  custom: ['Records', 'Members', 'Profiles', 'Accounts'],
};

const FIELDS_BY_SOURCE = {
  Graduates: ['student_id', 'full_name', 'graduation_date', 'program', 'cgpa', 'faculty', 'degree_type'],
  Students: ['student_id', 'full_name', 'enrollment_date', 'program', 'cgpa', 'status', 'faculty'],
  Employees: ['employee_id', 'full_name', 'department', 'position', 'start_date', 'employment_type', 'status'],
  Contractors: ['contractor_id', 'full_name', 'company', 'contract_start', 'contract_end', 'status'],
  Members: ['member_id', 'full_name', 'membership_type', 'join_date', 'expiry_date', 'status'],
  Alumni: ['alumni_id', 'full_name', 'graduation_year', 'program', 'chapter', 'status'],
  default: ['id', 'full_name', 'status', 'created_at', 'record_type'],
};

function getSourceFields(source) {
  return FIELDS_BY_SOURCE[source] || FIELDS_BY_SOURCE.default;
}

// ── Step indicator ─────────────────────────────────────────────────────────

const STEPS = [
  'Connect System',
  'Authenticate',
  'Discover Sources',
  'Select Source',
  'Discover Fields',
  'Configure',
  'Test',
  'Activate',
];

function StepBar({ current }) {
  return (
    <div className="flex items-center gap-0 overflow-x-auto pb-1 mb-6">
      {STEPS.map((label, i) => {
        const done = i < current;
        const active = i === current;
        return (
          <div key={i} className="flex items-center shrink-0">
            <div className="flex flex-col items-center">
              <div className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold transition-all ${
                done ? 'bg-primary text-primary-foreground' :
                active ? 'bg-primary/20 text-primary border-2 border-primary' :
                'bg-muted text-muted-foreground'
              }`}>
                {done ? <Check className="h-3.5 w-3.5" /> : i + 1}
              </div>
              <span className={`text-[10px] mt-0.5 font-medium whitespace-nowrap ${active ? 'text-primary' : done ? 'text-foreground' : 'text-muted-foreground'}`}>
                {label}
              </span>
            </div>
            {i < STEPS.length - 1 && (
              <div className={`h-0.5 w-8 mx-1 mb-3 transition-all ${done ? 'bg-primary' : 'bg-border'}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── Step 1: System Type ────────────────────────────────────────────────────

function Step1SystemType({ value, onChange, onNext }) {
  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Connect Organization System</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Choose the type of system your organization uses to manage records.
        </p>
      </div>
      <div className="grid grid-cols-2 gap-3">
        {SYSTEM_TYPES.map(({ id, label, icon: Icon, desc }) => (
          <button
            key={id}
            onClick={() => onChange(id)}
            className={`flex items-start gap-3 p-4 rounded-xl border text-left transition-all ${
              value === id
                ? 'border-primary bg-primary/5 ring-1 ring-primary'
                : 'border-border hover:border-primary/40 hover:bg-muted/40'
            }`}
          >
            <div className={`mt-0.5 rounded-lg p-2 ${value === id ? 'bg-primary/10 text-primary' : 'bg-muted text-muted-foreground'}`}>
              <Icon className="h-5 w-5" />
            </div>
            <div>
              <div className="text-sm font-medium text-foreground">{label}</div>
              <div className="text-xs text-muted-foreground mt-0.5">{desc}</div>
            </div>
            {value === id && <Check className="h-4 w-4 text-primary ml-auto mt-0.5 shrink-0" />}
          </button>
        ))}
      </div>
      <Button onClick={onNext} disabled={!value} className="w-full">
        Connect System <ChevronRight className="h-4 w-4 ml-1" />
      </Button>
    </div>
  );
}

// ── Step 2: Authentication ─────────────────────────────────────────────────

function Step2Auth({ authMethod, setAuthMethod, config, setConfig, onNext, onBack }) {
  const handleChange = (field, val) => setConfig(c => ({ ...c, [field]: val }));

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Authenticate Your System</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Provide connection details so the platform can securely reach your system.
        </p>
      </div>

      <div className="space-y-3">
        <label className="text-sm font-medium text-foreground">Base URL</label>
        <Input
          placeholder="https://api.yourorg.edu"
          value={config.api_base_url || ''}
          onChange={e => handleChange('api_base_url', e.target.value)}
        />
        <Input
          placeholder="/api/members/verify"
          value={config.member_verify_endpoint || '/api/members/verify'}
          onChange={e => handleChange('member_verify_endpoint', e.target.value)}
        />
      </div>

      <div className="space-y-3">
        <label className="text-sm font-medium text-foreground">Authentication Method</label>
        <div className="grid grid-cols-2 gap-2">
          {AUTH_METHODS.map(({ id, label, icon: Icon, desc }) => (
            <button
              key={id}
              onClick={() => setAuthMethod(id)}
              className={`flex items-start gap-2.5 p-3 rounded-lg border text-left transition-all ${
                authMethod === id
                  ? 'border-primary bg-primary/5 ring-1 ring-primary'
                  : 'border-border hover:border-primary/30'
              }`}
            >
              <Icon className={`h-4 w-4 mt-0.5 shrink-0 ${authMethod === id ? 'text-primary' : 'text-muted-foreground'}`} />
