                <div className="text-xs font-medium text-foreground">{label}</div>
                <div className="text-[10px] text-muted-foreground">{desc}</div>
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="space-y-3">
        {(authMethod === 'api_key' || authMethod === 'service_account') && (
          <div className="grid grid-cols-2 gap-3">
            <Input
              label="Header Name"
              placeholder="X-API-Key"
              value={config.api_key_header || 'X-API-Key'}
              onChange={e => handleChange('api_key_header', e.target.value)}
            />
            <Input
              label="Key / Token"
              type="password"
              placeholder="Enter secret key"
              value={config.api_key_value || ''}
              onChange={e => handleChange('api_key_value', e.target.value)}
            />
          </div>
        )}
        {authMethod === 'bearer' && (
          <Input
            label="Bearer Token"
            type="password"
            placeholder="eyJ..."
            value={config.api_key_value || ''}
            onChange={e => {
              handleChange('api_key_value', e.target.value);
              handleChange('api_key_header', 'Authorization');
            }}
          />
        )}
        {authMethod === 'basic' && (
          <div className="grid grid-cols-2 gap-3">
            <Input
              label="Username"
              placeholder="service_user"
              value={config.basic_user || ''}
              onChange={e => handleChange('basic_user', e.target.value)}
            />
            <Input
              label="Password"
              type="password"
              placeholder="••••••••"
              value={config.api_key_value || ''}
              onChange={e => {
                handleChange('api_key_value', e.target.value);
                handleChange('api_key_header', 'Authorization');
              }}
