          disabled={!config.api_base_url}
          className="flex-2 flex-grow"
        >
          Verify Connection <ShieldCheck className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 3: Discover Sources ───────────────────────────────────────────────

function Step3DiscoverSources({ systemType, orgName, sources, setSources, scanning, setScanning, onNext, onBack }) {
  const runScan = useCallback(() => {
    setScanning(true);
    setSources([]);
    setTimeout(() => {
      const discovered = SOURCES_BY_TYPE[systemType] || SOURCES_BY_TYPE.rest_api;
      setSources(discovered);
      setScanning(false);
    }, 2200);
  }, [systemType, setSources, setScanning]);

  useEffect(() => {
    if (sources.length === 0 && !scanning) runScan();
  }, []);

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Discover Available Sources</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Scanning your connected system for available record sources.
        </p>
      </div>

      <div className="card p-5 space-y-4">
        <div className="flex items-center gap-3">
          <div className={`rounded-full p-2 ${scanning ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-600 animate-pulse' : 'bg-green-100 dark:bg-green-900/30 text-green-600'}`}>
            {scanning ? <Loader2 className="h-5 w-5 animate-spin" /> : <Database className="h-5 w-5" />}
          </div>
          <div>
            <div className="text-sm font-medium text-foreground">
              {scanning ? 'Scanning system…' : `${orgName || 'Your Organization'} — Sources Found`}
            </div>
            <div className="text-xs text-muted-foreground">
              {scanning ? 'Discovering available record sources' : `${sources.length} sources detected`}
            </div>
          </div>
          {!scanning && (
            <button onClick={runScan} className="ml-auto text-muted-foreground hover:text-foreground">
              <RefreshCw className="h-4 w-4" />
            </button>
          )}
        </div>

        {scanning && (
          <div className="space-y-2">
            {[1, 2, 3].map(i => (
              <div key={i} className="h-9 rounded-lg bg-muted animate-pulse" style={{ animationDelay: `${i * 0.15}s` }} />
            ))}
          </div>
        )}

        {!scanning && sources.length > 0 && (
          <div className="space-y-2">
            {sources.map((src, i) => (
              <div
                key={src}
                className="flex items-center gap-3 px-3 py-2.5 rounded-lg bg-muted/40 border border-border"
                style={{ animationDelay: `${i * 0.05}s` }}
              >
                <CheckCircle2 className="h-4 w-4 text-green-500 shrink-0" />
                <span className="text-sm text-foreground font-medium">{src}</span>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="flex gap-3">
        <Button variant="outline" onClick={onBack} className="flex-1">
          <ArrowLeft className="h-4 w-4 mr-1" /> Back
        </Button>
        <Button onClick={onNext} disabled={scanning || sources.length === 0} className="flex-grow">
          Continue <ChevronRight className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 4: Select Source ──────────────────────────────────────────────────

