  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Available Fields</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Fields discovered from the <strong>{source}</strong> source.
        </p>
      </div>

      <div className="card p-5 space-y-4">
        <div className="flex items-center gap-3">
          <div className={`rounded-full p-2 ${scanning ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-600' : 'bg-green-100 dark:bg-green-900/30 text-green-600'}`}>
            {scanning ? <Loader2 className="h-5 w-5 animate-spin" /> : <Zap className="h-5 w-5" />}
          </div>
          <div>
            <div className="text-sm font-medium text-foreground">
              {scanning ? 'Retrieving available fields…' : `${fields.length} fields found`}
            </div>
            <div className="text-xs text-muted-foreground">
              {scanning ? `Inspecting ${source} records` : 'Select fields to map to credential claims'}
            </div>
          </div>
          {!scanning && (
            <button onClick={runScan} className="ml-auto text-muted-foreground hover:text-foreground">
              <RefreshCw className="h-4 w-4" />
            </button>
          )}
        </div>

        {scanning && (
          <div className="flex flex-wrap gap-2">
            {[1, 2, 3, 4, 5].map(i => (
              <div key={i} className="h-7 w-24 rounded-full bg-muted animate-pulse" />
            ))}
          </div>
        )}

        {!scanning && fields.length > 0 && (
          <div className="flex flex-wrap gap-2">
            {fields.map(f => (
              <span key={f} className="inline-flex items-center gap-1.5 text-xs font-mono bg-muted/60 border border-border text-foreground px-3 py-1.5 rounded-full">
                <span className="w-1.5 h-1.5 rounded-full bg-primary inline-block" />
                {f}
              </span>
