  const handleChange = (key, val) => setConfig(c => ({ ...c, [key]: val }));

  const addMapping = () => setFieldMappings(m => [...m, { response_path: '', credential_field: '' }]);
  const removeMapping = (i) => setFieldMappings(m => m.filter((_, idx) => idx !== i));
  const updateMapping = (i, key, val) => setFieldMappings(m => m.map((row, idx) => idx === i ? { ...row, [key]: val } : row));

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Create Credential Integration</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Map your system's fields to the credential that will be issued.
        </p>
      </div>

      <div className="card p-5 space-y-4">
        <h3 className="text-sm font-semibold text-foreground">Eligibility Configuration</h3>

        <div className="space-y-1">
          <label className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Identifier Field</label>
          <p className="text-xs text-muted-foreground mb-2">The field sent to your API to identify a record (e.g. national ID)</p>
          <select
            className="w-full h-9 rounded-lg border border-border bg-background text-foreground text-sm px-3 focus:outline-none focus:ring-2 focus:ring-primary/30"
            value={config.request_id_field || ''}
            onChange={e => handleChange('request_id_field', e.target.value)}
          >
            <option value="">Select identifier field…</option>
            {fields.map(f => <option key={f} value={f}>{f}</option>)}
            <option value="national_id">national_id (NID)</option>
          </select>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="space-y-1">
            <label className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Eligibility Field</label>
            <select
              className="w-full h-9 rounded-lg border border-border bg-background text-foreground text-sm px-3 focus:outline-none focus:ring-2 focus:ring-primary/30"
              value={config.response_eligibility_field || ''}
              onChange={e => handleChange('response_eligibility_field', e.target.value)}
            >
              <option value="">Select field…</option>
              {fields.map(f => <option key={f} value={f}>{f}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Eligible Value</label>
            <Input
              placeholder="completed / true / active"
              value={config.eligibility_value || ''}
              onChange={e => handleChange('eligibility_value', e.target.value)}
            />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-xs font-medium text-muted-foreground uppercase tracking-wide">Display Name Field</label>
          <select
            className="w-full h-9 rounded-lg border border-border bg-background text-foreground text-sm px-3 focus:outline-none focus:ring-2 focus:ring-primary/30"
            value={config.response_name_field || ''}
            onChange={e => handleChange('response_name_field', e.target.value)}
          >
            <option value="">Select name field…</option>
            {fields.map(f => <option key={f} value={f}>{f}</option>)}
          </select>
        </div>
      </div>

      <div className="card p-5 space-y-4">
        <div className="flex items-center justify-between">
          <div>
            <h3 className="text-sm font-semibold text-foreground">Field Mappings</h3>
            <p className="text-xs text-muted-foreground mt-0.5">Map source fields to credential claims</p>
          </div>
          <Button type="button" size="sm" variant="outline" onClick={addMapping}>
            <Plus className="h-3 w-3 mr-1" /> Add Field
          </Button>
        </div>

        {fieldMappings.length === 0 ? (
          <div className="py-6 text-center border border-dashed border-border rounded-xl">
            <p className="text-xs text-muted-foreground">No field mappings yet. Add fields from the discovered source.</p>
          </div>
        ) : (
          <div className="space-y-2">
            {fieldMappings.map((row, i) => (
              <div key={i} className="flex items-center gap-2">
                <select
                  className="flex-1 h-9 rounded-lg border border-border bg-background text-foreground text-sm px-2 focus:outline-none focus:ring-2 focus:ring-primary/30"
                  value={row.response_path}
                  onChange={e => updateMapping(i, 'response_path', e.target.value)}
                >
                  <option value="">Source field…</option>
                  {fields.map(f => <option key={f} value={f}>{f}</option>)}
                </select>
                <ArrowRight className="h-4 w-4 text-muted-foreground shrink-0" />
                <Input
                  className="flex-1"
                  placeholder="credentialFieldName"
                  value={row.credential_field}
                  onChange={e => updateMapping(i, 'credential_field', e.target.value)}
                />
                <button onClick={() => removeMapping(i)} className="text-red-400 hover:text-red-600 p-1">
                  <Trash2 className="h-4 w-4" />
                </button>
