                onClick={() => setFieldMappings(m => [...m, { response_path: f, credential_field: f }])}
                className="text-xs bg-primary/10 text-primary border border-primary/20 px-2.5 py-1 rounded-full hover:bg-primary/20 transition-colors"
              >
                + {f}
