          <ArrowLeft className="h-4 w-4 mr-1" /> Back
        </Button>
        <Button
          onClick={onNext}
          disabled={!config.request_id_field || !config.response_eligibility_field}
          className="flex-grow"
        >
          Test Integration <ChevronRight className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 7: Test Integration ───────────────────────────────────────────────

function Step7Test({ testMemberId, setTestMemberId, testing, setTesting, testResult, setTestResult, onNext, onBack }) {
  const handleTest = async () => {
    if (!testMemberId.trim()) { toast.error('Enter a test member ID'); return; }
    setTesting(true);
    setTestResult(null);
    try {
      const res = await testApiConfig({ test_member_id: testMemberId.trim() });
      setTestResult(res.data);
      if (res.data.success) toast.success('Integration test passed!');
      else toast.error('Test failed — see details');
    } catch (err) {
      const msg = err.response?.data?.error || 'Connection test failed';
      setTestResult({ success: false, error: msg });
      toast.error(msg);
    } finally { setTesting(false); }
  };

  const checks = testResult?.success
    ? [
        { label: 'Connected', ok: true },
        { label: 'Eligible Record Found', ok: !!testResult?.fields_found?.length },
        { label: 'Data Retrieved Successfully', ok: true },
      ]
    : null;

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Test Integration</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Run a live verification request to confirm everything is configured correctly.
        </p>
      </div>

      <div className="card p-5 space-y-4">
        <div className="flex gap-2 items-end">
          <div className="flex-1">
            <Input
              label="Test Member / Record ID"
              value={testMemberId}
              onChange={e => setTestMemberId(e.target.value)}
              placeholder="Enter a real record ID from your system"
            />
          </div>
          <Button onClick={handleTest} isLoading={testing} variant="outline" className="shrink-0">
            <Search className="h-4 w-4 mr-1" /> Test
          </Button>
        </div>

        {testing && (
          <div className="space-y-2">
            {['Sending verification request…', 'Checking eligibility…', 'Retrieving data…'].map((msg, i) => (
              <div key={i} className="flex items-center gap-2 text-sm text-muted-foreground">
                <Loader2 className="h-3.5 w-3.5 animate-spin" />
                {msg}
              </div>
            ))}
          </div>
        )}

        {testResult && (
          <div className={`rounded-xl border p-4 space-y-3 ${
            testResult.success
              ? 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800'
              : 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800'
          }`}>
            {testResult.success && checks && (
              <div className="space-y-1.5">
                {checks.map(({ label, ok }) => (
                  <div key={label} className="flex items-center gap-2 text-sm">
                    {ok
                      ? <CheckCircle2 className="h-4 w-4 text-green-500" />
                      : <XCircle className="h-4 w-4 text-red-400" />}
                    <span className={ok ? 'text-green-800 dark:text-green-200' : 'text-red-700 dark:text-red-300'}>{label}</span>
                  </div>
                ))}
              </div>
            )}

            {!testResult.success && (
              <div className="flex items-start gap-2 text-sm text-red-700 dark:text-red-300">
                <XCircle className="h-4 w-4 mt-0.5 shrink-0" />
                <span>{testResult.error || 'Connection failed. Check your configuration.'}</span>
              </div>
            )}

            {testResult.fields_found?.length > 0 && (
              <div>
                <p className="text-xs font-medium text-green-700 dark:text-green-300 mb-1.5">Fields retrieved:</p>
                <div className="flex flex-wrap gap-1.5">
                  {testResult.fields_found.map(f => (
                    <code key={f} className="text-xs bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-200 px-2 py-0.5 rounded-full font-mono">
                      {f}
                    </code>
                  ))}
                </div>
              </div>
            )}

            {testResult.raw_response && (
              <details className="text-xs">
                <summary className="cursor-pointer text-muted-foreground hover:text-foreground">View raw response</summary>
                <pre className="mt-2 bg-black/10 dark:bg-white/5 rounded-lg p-2 overflow-auto max-h-36 text-xs">
                  {JSON.stringify(testResult.raw_response, null, 2)}
                </pre>
              </details>
            )}
          </div>
        )}
      </div>

      <div className="flex gap-3">
        <Button variant="outline" onClick={onBack} className="flex-1">
          <ArrowLeft className="h-4 w-4 mr-1" /> Back
        </Button>
        <Button onClick={onNext} className="flex-grow" variant={testResult?.success ? 'default' : 'outline'}>
          {testResult?.success ? 'Activate Integration' : 'Skip & Activate'}
          <ChevronRight className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 8: Activate ───────────────────────────────────────────────────────

