      <div className="card p-5 space-y-4">
        <h3 className="text-sm font-semibold text-foreground">Integration Summary</h3>

        <div className="divide-y divide-border">
          {[
            { label: 'Source', value: source },
            { label: 'Endpoint', value: `${config.api_base_url || ''}${config.member_verify_endpoint || ''}` },
            { label: 'Identifier Field', value: config.request_id_field },
            { label: 'Eligibility Field', value: config.response_eligibility_field },
            { label: 'Name Field', value: config.response_name_field },
