export default function ApiConfigPage() {
  const [loading, setLoading] = useState(true);
  const [existingConfig, setExistingConfig] = useState(null);
  const [showWizard, setShowWizard] = useState(false);

  // Wizard state
  const [step, setStep] = useState(0);
  const [systemType, setSystemType] = useState('');
  const [authMethod, setAuthMethod] = useState('api_key');
  const [config, setConfig] = useState({
    api_base_url: '',
    member_verify_endpoint: '/api/members/verify',
    api_key_header: 'X-API-Key',
    api_key_value: '',
    request_id_field: 'member_id',
    response_eligibility_field: 'is_eligible',
    response_name_field: 'member.full_name',
  });
  const [sources, setSources] = useState([]);
  const [scanning3, setScanning3] = useState(false);
  const [selectedSource, setSelectedSource] = useState('');
  const [fields, setFields] = useState([]);
  const [scanning5, setScanning5] = useState(false);
  const [fieldMappings, setFieldMappings] = useState([]);
  const [testMemberId, setTestMemberId] = useState('');
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState(null);
  const [activating, setActivating] = useState(false);

  useEffect(() => {
    getApiConfig()
      .then(r => {
        if (r.data?.api_base_url) {
          setExistingConfig(r.data);
        } else {
          setShowWizard(true);
        }
      })
      .catch(() => setShowWizard(true))
      .finally(() => setLoading(false));
  }, []);

  const handleActivate = async () => {
    setActivating(true);
    try {
      await saveApiConfig({
        ...config,
        field_mappings: fieldMappings,
      });
      const r = await getApiConfig();
      setExistingConfig(r.data);
      setShowWizard(false);
      toast.success('Integration activated! You can now issue credentials.');
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to activate integration');
    } finally { setActivating(false); }
  };

  const handleReconfigure = () => {
    setStep(0);
    setShowWizard(true);
    setTestResult(null);
    setFields([]);
    setSources([]);
    setSelectedSource('');
  };

  if (loading) return <CardSkeleton />;

  if (!showWizard && existingConfig) {
    return <ActiveIntegration config={existingConfig} onReconfigure={handleReconfigure} />;
  }

  return (
    <div className="max-w-2xl space-y-2">
      <div className="mb-2">
        <h1 className="text-2xl font-bold text-foreground flex items-center gap-2">
          <Plug className="h-6 w-6" /> Organization Integration
        </h1>
        <p className="text-sm text-muted-foreground mt-1">
          Connect your organization's system in a few guided steps.
        </p>
      </div>

      <StepBar current={step} />

      <div className="card p-6">
        {step === 0 && (
          <Step1SystemType
            value={systemType}
            onChange={setSystemType}
            onNext={() => setStep(1)}
          />
        )}
        {step === 1 && (
          <Step2Auth
            authMethod={authMethod}
            setAuthMethod={setAuthMethod}
            config={config}
            setConfig={setConfig}
            onNext={() => setStep(2)}
            onBack={() => setStep(0)}
          />
        )}
        {step === 2 && (
          <Step3DiscoverSources
            systemType={systemType}
            orgName={config.api_base_url}
            sources={sources}
            setSources={setSources}
            scanning={scanning3}
            setScanning={setScanning3}
            onNext={() => setStep(3)}
            onBack={() => setStep(1)}
          />
        )}
        {step === 3 && (
          <Step4SelectSource
            sources={sources}
            selected={selectedSource}
            setSelected={setSelectedSource}
            onNext={() => { setFields([]); setStep(4); }}
            onBack={() => setStep(2)}
          />
        )}
        {step === 4 && (
          <Step5DiscoverFields
            source={selectedSource}
            fields={fields}
            setFields={setFields}
            scanning={scanning5}
            setScanning={setScanning5}
            onNext={() => setStep(5)}
            onBack={() => setStep(3)}
          />
        )}
        {step === 5 && (
          <Step6Configure
            fields={fields}
            config={config}
            setConfig={setConfig}
            fieldMappings={fieldMappings}
            setFieldMappings={setFieldMappings}
            onNext={() => setStep(6)}
            onBack={() => setStep(4)}
          />
        )}
        {step === 6 && (
          <Step7Test
            testMemberId={testMemberId}
            setTestMemberId={setTestMemberId}
            testing={testing}
            setTesting={setTesting}
            testResult={testResult}
            setTestResult={setTestResult}
            onNext={() => setStep(7)}
            onBack={() => setStep(5)}
          />
        )}
        {step === 7 && (
          <Step8Activate
            source={selectedSource}
            config={config}
            fieldMappings={fieldMappings}
            testResult={testResult}
            activating={activating}
            onActivate={handleActivate}
            onReset={() => setStep(0)}
          />
        )}
      </div>
    </div>
  );
}

