import { useEffect, useState, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTemplates, getTemplate, bulkIssueCredentials } from '../../api/issuer';
import Button from '../../components/common/Button';
import {
  CheckCircle2, XCircle, Download, UploadCloud, FileText,
  AlertCircle, ChevronRight, ArrowLeft, Check, Loader2,
  Users, Zap, FileSpreadsheet, RefreshCw, BadgeCheck,
} from 'lucide-react';
import toast from 'react-hot-toast';

// ── Helpers ────────────────────────────────────────────────────────────────

const STEPS = ['Select Template', 'Upload CSV', 'Review', 'Issue'];

const FAILURE_REASON_MAP = {
  member_not_eligible: 'Not found or not eligible',
  api_timeout: 'Member API timed out',
  api_error: 'Member API returned an error',
  invalid_response: 'Invalid API response',
  api_not_configured: 'Member API not configured',
  api_unreachable: 'Could not reach member API',
};

function friendlyReason(reason) {
  if (!reason) return 'Unknown error';
  for (const [key, label] of Object.entries(FAILURE_REASON_MAP)) {
    if (reason.toLowerCase().includes(key)) return label;
  }
  return reason;
}

function parseCsv(text) {
  const lines = text.trim().split(/\r?\n/);
  if (lines.length < 2) return { headers: [], rows: [] };
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
  const rows = lines.slice(1).map((line, i) => {
    const values = line.split(',').map(v => v.trim().replace(/^"|"$/g, ''));
    const row = { _rowNum: i + 2 };
    headers.forEach((h, idx) => { row[h] = values[idx] ?? ''; });
    return row;
  }).filter(row => Object.values(row).some((v, i) => i > 0 && v !== ''));
  return { headers, rows };
}

function buildSampleCsv(template) {
  if (!template) return `member_identifier\nNID-1234567890\nNID-0987654321\n`;
  const manualFields = (template.fields || []).filter(f => f.source === 'manual');
  const headers = ['member_identifier', ...manualFields.map(f => f.name)];
  const row1 = ['NID-1234567890', ...manualFields.map(f => f.label || f.name)];
  const row2 = ['NID-0987654321', ...manualFields.map(f => f.label || f.name)];
  return `${headers.join(',')}\n${row1.join(',')}\n${row2.join(',')}\n`;
}

function downloadCsv(content, filename) {
  const blob = new Blob([content], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

// ── Step Bar ───────────────────────────────────────────────────────────────

function StepBar({ current }) {
  return (
    <div className="flex items-center gap-0 mb-6">
      {STEPS.map((label, i) => {
        const done = i < current;
        const active = i === current;
        return (
          <div key={i} className="flex items-center shrink-0">
            <div className="flex flex-col items-center">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${
                done ? 'bg-primary text-primary-foreground' :
                active ? 'bg-primary/15 text-primary border-2 border-primary' :
                'bg-muted text-muted-foreground'
              }`}>
                {done ? <Check className="h-4 w-4" /> : i + 1}
              </div>
              <span className={`text-[10px] mt-1 font-medium whitespace-nowrap ${active ? 'text-primary' : done ? 'text-foreground' : 'text-muted-foreground'}`}>
                {label}
              </span>
            </div>
            {i < STEPS.length - 1 && (
              <div className={`h-0.5 w-12 mx-1 mb-3 transition-all ${done ? 'bg-primary' : 'bg-border'}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── Step 1: Select Template ────────────────────────────────────────────────

function Step1Template({ templates, selectedId, setSelectedId, selectedTemplate, loadingTemplate, onNext }) {
  const manualFields = (selectedTemplate?.fields || []).filter(f => f.source === 'manual');
  const apiFields = (selectedTemplate?.fields || []).filter(f => f.source === 'member_api');

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Select Credential Template</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Choose the credential type you want to issue in bulk.
        </p>
      </div>

      <div className="space-y-2">
        {templates.length === 0 && (
          <div className="py-10 text-center border border-dashed border-border rounded-xl">
            <BadgeCheck className="h-8 w-8 mx-auto mb-2 text-muted-foreground opacity-40" />
            <p className="text-sm text-muted-foreground">No active templates found.</p>
            <p className="text-xs text-muted-foreground mt-1">Activate a template first before issuing credentials.</p>
          </div>
        )}
        {templates.map(t => (
          <button
            key={t.id}
            onClick={() => setSelectedId(t.id)}
            className={`w-full flex items-start gap-3 px-4 py-3.5 rounded-xl border text-left transition-all ${
              selectedId === t.id
                ? 'border-primary bg-primary/5 ring-1 ring-primary'
                : 'border-border hover:border-primary/40 hover:bg-muted/30'
            }`}
          >
            <BadgeCheck className={`h-5 w-5 mt-0.5 shrink-0 ${selectedId === t.id ? 'text-primary' : 'text-muted-foreground'}`} />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium text-foreground">{t.name}</span>
                {t.version && <span className="text-[10px] bg-muted px-1.5 py-0.5 rounded text-muted-foreground">v{t.version}</span>}
              </div>
              {t.description && <p className="text-xs text-muted-foreground mt-0.5 truncate">{t.description}</p>}
            </div>
            {selectedId === t.id && <Check className="h-4 w-4 text-primary shrink-0 mt-0.5" />}
          </button>
        ))}
      </div>

      {loadingTemplate && (
        <div className="flex items-center gap-2 text-sm text-muted-foreground py-2">
          <Loader2 className="h-4 w-4 animate-spin" /> Loading template details…
        </div>
      )}

      {selectedTemplate && !loadingTemplate && (
        <div className="rounded-xl border border-border bg-muted/30 p-4 space-y-3">
          <p className="text-xs font-semibold text-foreground uppercase tracking-wide">Template Details</p>
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide">Auto-filled from API</p>
              {apiFields.length === 0
                ? <p className="text-xs text-muted-foreground italic">None</p>
                : apiFields.map(f => (
                  <div key={f.name} className="flex items-center gap-1.5 text-xs text-foreground">
                    <span className="w-1.5 h-1.5 rounded-full bg-blue-400 inline-block" />
                    {f.label || f.name}
                  </div>
                ))}
            </div>
            <div className="space-y-1">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide">Required CSV columns</p>
              <div className="flex items-center gap-1.5 text-xs text-foreground">
                <span className="w-1.5 h-1.5 rounded-full bg-primary inline-block" />
                member_identifier
              </div>
              {manualFields.map(f => (
                <div key={f.name} className="flex items-center gap-1.5 text-xs text-foreground">
                  <span className="w-1.5 h-1.5 rounded-full bg-orange-400 inline-block" />
                  {f.name}
                </div>
              ))}
            </div>
          </div>
          {selectedTemplate.issuance_rules?.expiry_days && (
            <p className="text-xs text-muted-foreground border-t border-border pt-2 mt-1">
              Credentials valid for <strong>{selectedTemplate.issuance_rules.expiry_days} days</strong>
            </p>
          )}
        </div>
      )}

      <Button onClick={onNext} disabled={!selectedId || !selectedTemplate} className="w-full">
        Continue <ChevronRight className="h-4 w-4 ml-1" />
      </Button>
    </div>
  );
}

// ── Step 2: Upload CSV ─────────────────────────────────────────────────────

function Step2Upload({ template, file, setFile, parsed, setParsed, onNext, onBack }) {
  const fileInputRef = useRef(null);
  const [dragging, setDragging] = useState(false);

  const handleFile = useCallback((f) => {
    if (!f || !f.name.endsWith('.csv')) {
      toast.error('Please upload a .csv file');
      return;
    }
    setFile(f);
    const reader = new FileReader();
    reader.onload = e => {
      const result = parseCsv(e.target.result);
      setParsed(result);
    };
    reader.readAsText(f);
  }, [setFile, setParsed]);

  const onDrop = useCallback(e => {
    e.preventDefault();
    setDragging(false);
    const f = e.dataTransfer.files?.[0];
    if (f) handleFile(f);
  }, [handleFile]);

  const onDragOver = e => { e.preventDefault(); setDragging(true); };
  const onDragLeave = () => setDragging(false);

  const manualFields = (template?.fields || []).filter(f => f.source === 'manual');
  const requiredHeaders = ['member_identifier', ...manualFields.map(f => f.name)];

  const missingColumns = parsed?.headers
    ? requiredHeaders.filter(h => !parsed.headers.includes(h))
    : [];

  const canProceed = file && parsed?.rows?.length > 0 && missingColumns.length === 0;

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Upload CSV File</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Upload a CSV with one row per recipient. Each row will be verified against your organization's system.
        </p>
      </div>

      <div className="flex items-center justify-between">
        <p className="text-xs text-muted-foreground">
          Required columns: {requiredHeaders.map(h => (
            <code key={h} className="mx-0.5 bg-muted px-1.5 py-0.5 rounded text-foreground">{h}</code>
          ))}
        </p>
        <button
          onClick={() => downloadCsv(buildSampleCsv(template), `sample_${template?.name?.replace(/\s+/g, '_') || 'bulk'}.csv`)}
          className="text-xs text-primary hover:underline flex items-center gap-1 shrink-0"
        >
          <Download className="h-3 w-3" /> Download sample
        </button>
      </div>

      <div
        onDrop={onDrop}
        onDragOver={onDragOver}
        onDragLeave={onDragLeave}
        onClick={() => fileInputRef.current?.click()}
        className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all ${
          dragging ? 'border-primary bg-primary/5 scale-[1.01]' :
          file && canProceed ? 'border-green-400 bg-green-50 dark:bg-green-900/10' :
          file && missingColumns.length > 0 ? 'border-red-300 bg-red-50 dark:bg-red-900/10' :
          'border-border hover:border-primary/50 hover:bg-muted/20'
        }`}
      >
        <input
          ref={fileInputRef}
          type="file"
          accept=".csv"
          className="hidden"
          onChange={e => handleFile(e.target.files?.[0])}
        />
        {file ? (
          <div className="space-y-1">
            <FileSpreadsheet className={`h-8 w-8 mx-auto ${canProceed ? 'text-green-500' : 'text-red-400'}`} />
            <p className="text-sm font-medium text-foreground mt-2">{file.name}</p>
            <p className="text-xs text-muted-foreground">{(file.size / 1024).toFixed(1)} KB</p>
            {parsed?.rows?.length > 0 && (
              <p className="text-xs font-medium text-foreground">{parsed.rows.length} rows detected</p>
            )}
            <button
              onClick={e => { e.stopPropagation(); setFile(null); setParsed(null); if (fileInputRef.current) fileInputRef.current.value = ''; }}
              className="text-xs text-red-500 hover:text-red-700 mt-1"
            >
              Remove file
            </button>
          </div>
        ) : (
          <div className="text-muted-foreground">
            <UploadCloud className={`h-10 w-10 mx-auto mb-3 transition-transform ${dragging ? 'scale-110 text-primary' : 'opacity-40'}`} />
            <p className="text-sm font-medium">Drop your CSV here or click to browse</p>
            <p className="text-xs mt-1 opacity-60">Supports .csv files only</p>
          </div>
        )}
      </div>

      {missingColumns.length > 0 && (
        <div className="flex items-start gap-2.5 p-3.5 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800">
          <XCircle className="h-4 w-4 text-red-500 shrink-0 mt-0.5" />
          <div className="text-sm text-red-700 dark:text-red-300">
            <strong>Missing columns:</strong>{' '}
            {missingColumns.map(c => <code key={c} className="mx-0.5 bg-red-100 dark:bg-red-900/40 px-1.5 py-0.5 rounded">{c}</code>)}
            <p className="text-xs mt-1 opacity-80">Download the sample CSV above for the correct format.</p>
          </div>
        </div>
      )}

      {parsed?.rows?.length > 0 && canProceed && (
        <div className="flex items-center gap-2.5 p-3.5 rounded-xl bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
          <CheckCircle2 className="h-4 w-4 text-green-500 shrink-0" />
          <span className="text-sm text-green-700 dark:text-green-300">
            <strong>{parsed.rows.length} records</strong> ready for issuance
          </span>
        </div>
      )}

      <div className="flex gap-3">
        <Button variant="outline" onClick={onBack} className="flex-1">
          <ArrowLeft className="h-4 w-4 mr-1" /> Back
        </Button>
        <Button onClick={onNext} disabled={!canProceed} className="flex-grow">
          Preview Records <ChevronRight className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 3: Review ─────────────────────────────────────────────────────────

function Step3Review({ template, parsed, file, onNext, onBack, issuing }) {
  const manualFields = (template?.fields || []).filter(f => f.source === 'manual');
  const visibleHeaders = ['member_identifier', ...manualFields.map(f => f.name)];
  const rows = parsed?.rows || [];
  const displayRows = rows.slice(0, 50);

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Review Records</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Confirm the records below before issuing. Each row will be verified against your organization's system at issuance time.
        </p>
      </div>

      <div className="grid grid-cols-3 gap-3">
        {[
          { label: 'Records', value: rows.length, icon: Users, color: 'text-foreground' },
          { label: 'Template', value: template?.name, icon: BadgeCheck, color: 'text-primary', small: true },
          { label: 'File', value: file?.name, icon: FileText, color: 'text-foreground', small: true },
        ].map(({ label, value, icon: Icon, color, small }) => (
          <div key={label} className="card p-3 text-center space-y-1">
            <Icon className={`h-5 w-5 mx-auto ${color} opacity-70`} />
            <p className={`font-bold ${small ? 'text-xs' : 'text-2xl'} ${color} truncate`}>{value ?? '—'}</p>
            <p className="text-[10px] text-muted-foreground uppercase tracking-wide">{label}</p>
          </div>
        ))}
      </div>

      <div className="card overflow-hidden">
        <div className="px-4 py-3 border-b border-border flex items-center justify-between">
          <p className="text-xs font-semibold text-foreground uppercase tracking-wide">
            Preview ({Math.min(rows.length, 50)} of {rows.length} rows)
          </p>
          {rows.length > 50 && (
            <span className="text-xs text-muted-foreground">{rows.length - 50} more rows not shown</span>
          )}
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-xs">
            <thead className="bg-muted/40">
              <tr>
                <th className="text-left px-3 py-2 text-muted-foreground font-medium w-8">#</th>
                {visibleHeaders.map(h => (
                  <th key={h} className="text-left px-3 py-2 text-muted-foreground font-medium">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {displayRows.map((row, i) => (
                <tr key={i} className="hover:bg-muted/20">
                  <td className="px-3 py-2 text-muted-foreground">{row._rowNum}</td>
                  {visibleHeaders.map(h => (
                    <td key={h} className="px-3 py-2 font-mono text-foreground max-w-[160px] truncate">
                      {row[h] || <span className="text-muted-foreground italic">—</span>}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <div className="flex items-start gap-3 p-3.5 rounded-xl bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
        <Zap className="h-4 w-4 text-blue-500 shrink-0 mt-0.5" />
        <p className="text-xs text-blue-700 dark:text-blue-300">
          Each record will be individually verified against your connected organization system. 
          Ineligible records are skipped and reported in the results.
        </p>
      </div>

      <div className="flex gap-3">
        <Button variant="outline" onClick={onBack} disabled={issuing} className="flex-1">
          <ArrowLeft className="h-4 w-4 mr-1" /> Back
        </Button>
        <Button onClick={onNext} isLoading={issuing} className="flex-grow bg-green-600 hover:bg-green-700">
          <Zap className="h-4 w-4 mr-1.5" />
          {issuing ? `Issuing ${rows.length} credentials…` : `Issue ${rows.length} Credentials`}
        </Button>
      </div>
    </div>
  );
}

// ── Step 4: Results ────────────────────────────────────────────────────────

function Step4Results({ result, totalRows, template, onReset }) {
  const navigate = useNavigate();
  const failedCount = result ? (result.failed_count ?? result.failed ?? 0) : 0;
  const issuedCount = result?.issued ?? 0;
  const successRate = totalRows > 0 ? Math.round((issuedCount / totalRows) * 100) : 0;

  const downloadFailures = () => {
    if (!result?.failures?.length) return;
    const headers = ['member_identifier', 'reason'];
    const rows = result.failures.map(f => `${f.member_identifier},${friendlyReason(f.reason)}`);
    downloadCsv(`${headers.join(',')}\n${rows.join('\n')}`, `failed_records_${template?.name?.replace(/\s+/g, '_') || 'bulk'}.csv`);
  };

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Issuance Complete</h2>
        <p className="text-sm text-muted-foreground mt-1">
          Bulk issuance finished. Review the results below.
        </p>
      </div>

      <div className="grid grid-cols-3 gap-3">
        {[
          { label: 'Total Rows', value: result?.total ?? totalRows, color: 'text-foreground' },
          { label: 'Issued', value: issuedCount, color: 'text-green-600 dark:text-green-400' },
          { label: 'Failed', value: failedCount, color: failedCount > 0 ? 'text-red-500' : 'text-muted-foreground' },
        ].map(s => (
          <div key={s.label} className="card p-4 text-center">
            <p className={`text-3xl font-bold ${s.color}`}>{s.value ?? 0}</p>
            <p className="text-xs text-muted-foreground mt-1">{s.label}</p>
          </div>
        ))}
      </div>

      {issuedCount > 0 && (
        <div className="rounded-xl border border-green-200 dark:border-green-800 bg-green-50 dark:bg-green-900/20 p-4">
          <div className="flex items-center gap-2 mb-2">
            <CheckCircle2 className="h-5 w-5 text-green-500" />
            <span className="text-sm font-semibold text-green-800 dark:text-green-200">
              {issuedCount} credential{issuedCount !== 1 ? 's' : ''} issued successfully ({successRate}%)
            </span>
          </div>
          <div className="w-full bg-green-200 dark:bg-green-800/50 rounded-full h-2">
            <div
              className="bg-green-500 h-2 rounded-full transition-all"
              style={{ width: `${successRate}%` }}
            />
          </div>
        </div>
      )}

      {result?.failures?.length > 0 && (
        <div className="card overflow-hidden">
          <div className="px-4 py-3 border-b border-border flex items-center justify-between">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-4 w-4 text-red-500" />
              <span className="text-sm font-semibold text-foreground">
                {failedCount} Failed Record{failedCount !== 1 ? 's' : ''}
              </span>
            </div>
            <button
              onClick={downloadFailures}
              className="text-xs text-primary hover:underline flex items-center gap-1"
            >
              <Download className="h-3 w-3" /> Export failures
            </button>
          </div>
          <div className="overflow-x-auto max-h-60">
            <table className="w-full text-xs">
              <thead className="bg-muted/40 sticky top-0">
                <tr>
                  <th className="text-left px-4 py-2 text-muted-foreground font-medium">Member ID</th>
                  <th className="text-left px-4 py-2 text-muted-foreground font-medium">Reason</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {result.failures.map((f, i) => (
                  <tr key={i} className="hover:bg-muted/20">
                    <td className="px-4 py-2 font-mono text-foreground">{f.member_identifier}</td>
                    <td className="px-4 py-2 text-red-500">{friendlyReason(f.reason)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <div className="flex gap-3">
        <Button variant="outline" onClick={onReset} className="flex-1">
          <RefreshCw className="h-4 w-4 mr-1" /> Issue Another Batch
        </Button>
        {issuedCount > 0 && (
          <Button onClick={() => navigate('/issuer/issued')} className="flex-grow">
            View Issued Credentials <ChevronRight className="h-4 w-4 ml-1" />
          </Button>
        )}
      </div>
    </div>
  );
}

// ── Main Component ─────────────────────────────────────────────────────────

export default function BulkIssuancePage() {
  const [step, setStep] = useState(0);
  const [templates, setTemplates] = useState([]);
  const [selectedTemplateId, setSelectedTemplateId] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [loadingTemplate, setLoadingTemplate] = useState(false);
  const [file, setFile] = useState(null);
  const [parsed, setParsed] = useState(null);
  const [issuing, setIssuing] = useState(false);
  const [result, setResult] = useState(null);

  useEffect(() => {
    getTemplates({ is_active: true })
      .then(r => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedTemplateId) { setSelectedTemplate(null); return; }
    setLoadingTemplate(true);
    getTemplate(selectedTemplateId)
      .then(r => setSelectedTemplate(r.data))
      .catch(() => {})
      .finally(() => setLoadingTemplate(false));
  }, [selectedTemplateId]);

  const handleIssue = async () => {
    if (!selectedTemplateId || !file) return;
    setIssuing(true);
    setResult(null);
    const fd = new FormData();
    fd.append('template_id', selectedTemplateId);
    fd.append('csv_file', file);
    try {
      const res = await bulkIssueCredentials(fd);
      setResult(res.data);
      setStep(3);
      const issued = res.data?.issued ?? 0;
      const failed = res.data?.failed_count ?? res.data?.failed ?? 0;
      if (issued > 0) toast.success(`${issued} credential${issued !== 1 ? 's' : ''} issued`);
      if (failed > 0) toast.error(`${failed} record${failed !== 1 ? 's' : ''} failed`);
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Bulk issuance failed');
    } finally { setIssuing(false); }
  };

  const handleReset = () => {
    setStep(0);
    setFile(null);
    setParsed(null);
    setResult(null);
    setSelectedTemplateId('');
    setSelectedTemplate(null);
  };

  return (
    <div className="max-w-2xl space-y-2">
      <div className="mb-2">
        <h1 className="text-2xl font-bold text-foreground">Bulk Issuance</h1>
        <p className="text-sm text-muted-foreground mt-1">
          Issue credentials to multiple recipients at once via CSV upload.
        </p>
      </div>

      <StepBar current={step} />

      <div className="card p-6">
        {step === 0 && (
          <Step1Template
            templates={templates}
            selectedId={selectedTemplateId}
            setSelectedId={setSelectedTemplateId}
            selectedTemplate={selectedTemplate}
            loadingTemplate={loadingTemplate}
            onNext={() => setStep(1)}
          />
        )}
        {step === 1 && (
          <Step2Upload
            template={selectedTemplate}
            file={file}
            setFile={setFile}
            parsed={parsed}
            setParsed={setParsed}
            onNext={() => setStep(2)}
            onBack={() => setStep(0)}
          />
        )}
        {step === 2 && (
          <Step3Review
            template={selectedTemplate}
            parsed={parsed}
            file={file}
            onNext={handleIssue}
            onBack={() => setStep(1)}
            issuing={issuing}
          />
        )}
        {step === 3 && (
          <Step4Results
            result={result}
            totalRows={parsed?.rows?.length || 0}
            template={selectedTemplate}
            onReset={handleReset}
          />
        )}
      </div>
    </div>
  );
}

