import { useEffect, useState, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTemplates, getTemplate, issueCredential } from '../../api/issuer';
import Button from '../../components/common/Button';
import {
  CheckCircle2, XCircle, Download, UploadCloud, FileText,
  AlertCircle, ChevronRight, ArrowLeft, Check, Loader2,
  Users, Zap, FileSpreadsheet, RefreshCw, BadgeCheck,
  CircleDot, Square, Clock,
} from 'lucide-react';
import toast from 'react-hot-toast';

// ── Helpers ────────────────────────────────────────────────────────────────

const STEPS = ['Select Template', 'Upload CSV', 'Review', 'Processing'];

const STEP_SELECT = 0;
const STEP_UPLOAD = 1;
const STEP_REVIEW = 2;
const STEP_PROCESS = 3;

const FAILURE_REASONS = {
  member_not_eligible: 'Not found or not eligible',
  api_timeout: 'Member API timed out',
  api_error: 'Member API error',
  invalid_response: 'Invalid API response',
  api_not_configured: 'Member API not configured',
  api_unreachable: 'Could not reach member API',
  not_associated: 'Not associated with an issuer org',
};

function friendlyReason(msg = '') {
  const lower = msg.toLowerCase();
  for (const [key, label] of Object.entries(FAILURE_REASONS)) {
    if (lower.includes(key.replace(/_/g, ' ')) || lower.includes(key)) return label;
  }
  return msg.length > 80 ? msg.slice(0, 80) + '…' : msg || 'Unknown error';
}

function parseCsv(text) {
  const lines = text.trim().split(/\r?\n/);
  if (lines.length < 2) return { headers: [], rows: [] };
  const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
  const rows = lines.slice(1)
    .map((line, i) => {
      const values = line.split(',').map(v => v.trim().replace(/^"|"$/g, ''));
      const row = { _rowNum: i + 2 };
      headers.forEach((h, idx) => { row[h] = values[idx] ?? ''; });
      return row;
    })
    .filter(row => headers.some(h => row[h] !== ''));
  return { headers, rows };
}

function buildSampleCsv(template) {
  if (!template) return 'member_identifier\nNID-1234567890\nNID-0987654321\n';
  const manual = (template.fields || []).filter(f => f.source === 'manual');
  const headers = ['member_identifier', ...manual.map(f => f.name)];
  const row1 = ['NID-1234567890', ...manual.map(f => f.label || f.name)];
  const row2 = ['NID-0987654321', ...manual.map(f => f.label || f.name)];
  return `${headers.join(',')}\n${row1.join(',')}\n${row2.join(',')}\n`;
}

function downloadCsv(content, filename) {
  const blob = new Blob([content], { type: 'text/csv' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  URL.revokeObjectURL(url);
}

function formatEta(secsRemaining) {
  if (secsRemaining < 60) return `~${Math.ceil(secsRemaining)}s remaining`;
  return `~${Math.ceil(secsRemaining / 60)}m remaining`;
}

// ── Step Bar ───────────────────────────────────────────────────────────────

function StepBar({ current }) {
  return (
    <div className="flex items-center mb-6">
      {STEPS.map((label, i) => {
        const done = i < current;
        const active = i === current;
        return (
          <div key={i} className="flex items-center shrink-0">
            <div className="flex flex-col items-center">
              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold transition-all ${
                done ? 'bg-primary text-primary-foreground' :
                active ? 'bg-primary/15 text-primary border-2 border-primary' :
                'bg-muted text-muted-foreground'
              }`}>
                {done ? <Check className="h-4 w-4" /> : i + 1}
              </div>
              <span className={`text-[10px] mt-1 font-medium whitespace-nowrap ${
                active ? 'text-primary' : done ? 'text-foreground' : 'text-muted-foreground'
              }`}>{label}</span>
            </div>
            {i < STEPS.length - 1 && (
              <div className={`h-0.5 w-12 mx-1 mb-3 transition-all ${done ? 'bg-primary' : 'bg-border'}`} />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── Step 1: Select Template ────────────────────────────────────────────────

function Step1Template({ templates, selectedId, setSelectedId, selectedTemplate, loadingTemplate, onNext }) {
  const manualFields = (selectedTemplate?.fields || []).filter(f => f.source === 'manual');
  const apiFields    = (selectedTemplate?.fields || []).filter(f => f.source === 'member_api');

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Select Credential Template</h2>
        <p className="text-sm text-muted-foreground mt-1">Choose the credential type to issue in bulk.</p>
      </div>

      <div className="space-y-2">
        {templates.length === 0 && (
          <div className="py-10 text-center border border-dashed border-border rounded-xl">
            <BadgeCheck className="h-8 w-8 mx-auto mb-2 text-muted-foreground opacity-40" />
            <p className="text-sm text-muted-foreground">No active templates — activate one first.</p>
          </div>
        )}
        {templates.map(t => (
          <button key={t.id} onClick={() => setSelectedId(t.id)}
            className={`w-full flex items-start gap-3 px-4 py-3.5 rounded-xl border text-left transition-all ${
              selectedId === t.id
                ? 'border-primary bg-primary/5 ring-1 ring-primary'
                : 'border-border hover:border-primary/40 hover:bg-muted/30'
            }`}>
            <BadgeCheck className={`h-5 w-5 mt-0.5 shrink-0 ${selectedId === t.id ? 'text-primary' : 'text-muted-foreground'}`} />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2">
                <span className="text-sm font-medium text-foreground">{t.name}</span>
                {t.version && <span className="text-[10px] bg-muted px-1.5 py-0.5 rounded text-muted-foreground">v{t.version}</span>}
              </div>
              {t.description && <p className="text-xs text-muted-foreground mt-0.5 truncate">{t.description}</p>}
            </div>
            {selectedId === t.id && <Check className="h-4 w-4 text-primary shrink-0 mt-0.5" />}
          </button>
        ))}
      </div>

      {loadingTemplate && (
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <Loader2 className="h-4 w-4 animate-spin" /> Loading template…
        </div>
      )}

      {selectedTemplate && !loadingTemplate && (
        <div className="rounded-xl border border-border bg-muted/30 p-4 space-y-3">
          <p className="text-xs font-semibold uppercase tracking-wide text-foreground">Template Details</p>
          <div className="grid grid-cols-2 gap-3 text-xs">
            <div className="space-y-1">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide">Auto-filled from API</p>
              {apiFields.length === 0
                ? <p className="text-muted-foreground italic">None</p>
                : apiFields.map(f => (
                  <div key={f.name} className="flex items-center gap-1.5 text-foreground">
                    <span className="w-1.5 h-1.5 rounded-full bg-blue-400 inline-block" />{f.label || f.name}
                  </div>
                ))}
            </div>
            <div className="space-y-1">
              <p className="text-[10px] text-muted-foreground uppercase tracking-wide">Required CSV columns</p>
              <div className="flex items-center gap-1.5 text-foreground">
                <span className="w-1.5 h-1.5 rounded-full bg-primary inline-block" />member_identifier
              </div>
              {manualFields.map(f => (
                <div key={f.name} className="flex items-center gap-1.5 text-foreground">
                  <span className="w-1.5 h-1.5 rounded-full bg-orange-400 inline-block" />{f.name}
                </div>
              ))}
            </div>
          </div>
          {selectedTemplate.issuance_rules?.expiry_days && (
            <p className="text-xs text-muted-foreground border-t border-border pt-2">
              Valid for <strong>{selectedTemplate.issuance_rules.expiry_days} days</strong>
            </p>
          )}
        </div>
      )}

      <Button onClick={onNext} disabled={!selectedId || !selectedTemplate} className="w-full">
        Continue <ChevronRight className="h-4 w-4 ml-1" />
      </Button>
    </div>
  );
}

// ── Step 2: Upload CSV ─────────────────────────────────────────────────────

function Step2Upload({ template, file, setFile, parsed, setParsed, onNext, onBack }) {
  const fileInputRef = useRef(null);
  const [dragging, setDragging] = useState(false);

  const handleFile = useCallback((f) => {
    if (!f) return;
    if (!f.name.endsWith('.csv')) { toast.error('Please upload a .csv file'); return; }
    setFile(f);
    const reader = new FileReader();
    reader.onload = e => setParsed(parseCsv(e.target.result));
    reader.readAsText(f);
  }, [setFile, setParsed]);

  const onDrop = useCallback(e => {
    e.preventDefault(); setDragging(false);
    handleFile(e.dataTransfer.files?.[0]);
  }, [handleFile]);

  const manual = (template?.fields || []).filter(f => f.source === 'manual');
  const required = ['member_identifier', ...manual.map(f => f.name)];
  const missing = parsed?.headers ? required.filter(h => !parsed.headers.includes(h)) : [];
  const canProceed = file && (parsed?.rows?.length ?? 0) > 0 && missing.length === 0;

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Upload CSV File</h2>
        <p className="text-sm text-muted-foreground mt-1">One row per recipient — each will be verified against your connected system in real time.</p>
      </div>

      <div className="flex items-center justify-between">
        <div className="flex flex-wrap gap-1 items-center text-xs text-muted-foreground">
          Required:{' '}
          {required.map(h => <code key={h} className="mx-0.5 bg-muted px-1.5 py-0.5 rounded text-foreground">{h}</code>)}
        </div>
        <button onClick={() => downloadCsv(buildSampleCsv(template), `sample_${template?.name?.replace(/\s+/g, '_') || 'bulk'}.csv`)}
          className="text-xs text-primary hover:underline flex items-center gap-1 shrink-0 ml-2">
          <Download className="h-3 w-3" /> Sample CSV
        </button>
      </div>

      <div
        onDrop={onDrop}
        onDragOver={e => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onClick={() => fileInputRef.current?.click()}
        className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all ${
          dragging ? 'border-primary bg-primary/5 scale-[1.01]' :
          canProceed ? 'border-green-400 bg-green-50 dark:bg-green-900/10' :
          file && missing.length > 0 ? 'border-red-300 bg-red-50 dark:bg-red-900/10' :
          'border-border hover:border-primary/50 hover:bg-muted/20'
        }`}>
        <input ref={fileInputRef} type="file" accept=".csv" className="hidden"
          onChange={e => handleFile(e.target.files?.[0])} />
        {file ? (
          <div className="space-y-1">
            <FileSpreadsheet className={`h-8 w-8 mx-auto ${canProceed ? 'text-green-500' : 'text-red-400'}`} />
            <p className="text-sm font-medium text-foreground mt-2">{file.name}</p>
            <p className="text-xs text-muted-foreground">{(file.size / 1024).toFixed(1)} KB</p>
            {parsed?.rows?.length > 0 && <p className="text-xs font-medium text-foreground">{parsed.rows.length} rows detected</p>}
            <button onClick={e => { e.stopPropagation(); setFile(null); setParsed(null); if (fileInputRef.current) fileInputRef.current.value = ''; }}
              className="text-xs text-red-500 hover:text-red-700 mt-1">Remove</button>
          </div>
        ) : (
          <div className="text-muted-foreground">
            <UploadCloud className={`h-10 w-10 mx-auto mb-3 transition-transform ${dragging ? 'scale-110 text-primary' : 'opacity-40'}`} />
            <p className="text-sm font-medium">Drop your CSV here or click to browse</p>
            <p className="text-xs mt-1 opacity-60">.csv files only</p>
          </div>
        )}
      </div>

      {missing.length > 0 && (
        <div className="flex items-start gap-2.5 p-3.5 rounded-xl bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800">
          <XCircle className="h-4 w-4 text-red-500 shrink-0 mt-0.5" />
          <div className="text-sm text-red-700 dark:text-red-300">
            <strong>Missing columns: </strong>
            {missing.map(c => <code key={c} className="mx-0.5 bg-red-100 dark:bg-red-900/40 px-1.5 py-0.5 rounded">{c}</code>)}
            <p className="text-xs mt-1 opacity-80">Download the sample CSV above for the correct format.</p>
          </div>
        </div>
      )}

      {canProceed && (
        <div className="flex items-center gap-2 p-3 rounded-xl bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
          <CheckCircle2 className="h-4 w-4 text-green-500 shrink-0" />
          <span className="text-sm text-green-700 dark:text-green-300">
            <strong>{parsed.rows.length} records</strong> ready
          </span>
        </div>
      )}

      <div className="flex gap-3">
        <Button variant="outline" onClick={onBack} className="flex-1"><ArrowLeft className="h-4 w-4 mr-1" /> Back</Button>
        <Button onClick={onNext} disabled={!canProceed} className="flex-grow">
          Preview Records <ChevronRight className="h-4 w-4 ml-1" />
        </Button>
      </div>
    </div>
  );
}

// ── Step 3: Review ─────────────────────────────────────────────────────────

function Step3Review({ template, parsed, file, onStart, onBack }) {
  const manual = (template?.fields || []).filter(f => f.source === 'manual');
  const visibleHeaders = ['member_identifier', ...manual.map(f => f.name)];
  const rows = parsed?.rows || [];

  return (
    <div className="space-y-5">
      <div>
        <h2 className="text-xl font-semibold text-foreground">Review Records</h2>
