}

// ── Step 4: Live Processing Feed ───────────────────────────────────────────

function Step4Processing({ rows, template, processedRows, isRunning, abortRef, onDone, onReset }) {
  const navigate = useNavigate();
  const feedRef = useRef(null);

  const total    = rows.length;
  const done     = processedRows.length;
  const issued   = processedRows.filter(r => r.status === 'issued').length;
  const failed   = processedRows.filter(r => r.status === 'failed').length;
  const pct      = total > 0 ? Math.round((done / total) * 100) : 0;
  const finished = done === total;

  const avgMs    = useRef(0);
  const startMs  = useRef(Date.now());

  // Keep average pace
  useEffect(() => {
    if (done > 0) avgMs.current = (Date.now() - startMs.current) / done;
  }, [done]);

  const remaining    = total - done;
  const etaSecs      = avgMs.current > 0 ? (remaining * avgMs.current) / 1000 : null;

  // Auto-scroll feed to bottom
  useEffect(() => {
    if (feedRef.current) feedRef.current.scrollTop = feedRef.current.scrollHeight;
  }, [processedRows.length]);

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-start justify-between">
        <div>
          <h2 className="text-xl font-semibold text-foreground">
            {finished ? 'Issuance Complete' : 'Issuing Credentials…'}
          </h2>
          <p className="text-sm text-muted-foreground mt-1">
            {finished
              ? `Finished — ${issued} issued, ${failed} failed.`
              : `Processing record ${done + 1} of ${total}${etaSecs ? ' · ' + formatEta(etaSecs) : ''}`}
          </p>
        </div>
        {isRunning && (
          <button
            onClick={() => { abortRef.current = true; }}
            className="flex items-center gap-1.5 text-xs text-red-500 hover:text-red-700 border border-red-200 dark:border-red-800 rounded-lg px-3 py-1.5 transition-colors"
          >
            <Square className="h-3 w-3" /> Stop
          </button>
        )}
      </div>

      {/* Progress bar */}
      <div className="space-y-2">
        <div className="flex justify-between text-xs text-muted-foreground">
          <span>{done} / {total} records</span>
          <span>{pct}%</span>
        </div>
        <div className="w-full bg-muted rounded-full h-2.5 overflow-hidden">
          <div
            className={`h-2.5 rounded-full transition-all duration-300 ${finished && failed === 0 ? 'bg-green-500' : finished && failed > 0 ? 'bg-primary' : 'bg-primary'}`}
            style={{ width: `${pct}%` }}
          />
        </div>
      </div>

      {/* Stats strip */}
      <div className="grid grid-cols-3 gap-3">
        {[
          { label: 'Processed', value: done, color: 'text-foreground' },
          { label: 'Issued',    value: issued, color: 'text-green-600 dark:text-green-400' },
          { label: 'Failed',    value: failed, color: failed > 0 ? 'text-red-500' : 'text-muted-foreground' },
        ].map(s => (
          <div key={s.label} className="card p-3 text-center">
            <p className={`text-2xl font-bold ${s.color}`}>{s.value}</p>
            <p className="text-[10px] text-muted-foreground uppercase tracking-wide mt-1">{s.label}</p>
          </div>
        ))}
      </div>

      {/* Live feed */}
      <div className="card overflow-hidden">
        <div className="px-4 py-2.5 border-b border-border flex items-center gap-2">
          {isRunning
            ? <><CircleDot className="h-3.5 w-3.5 text-red-500 animate-pulse" /><span className="text-xs font-semibold text-foreground">Live Feed</span></>
            : <><CheckCircle2 className="h-3.5 w-3.5 text-green-500" /><span className="text-xs font-semibold text-foreground">Complete</span></>}
        </div>
        <div ref={feedRef} className="overflow-y-auto max-h-64 divide-y divide-border">
          {processedRows.length === 0 && (
            <div className="flex items-center gap-2 px-4 py-3 text-xs text-muted-foreground">
              <Loader2 className="h-3.5 w-3.5 animate-spin" /> Starting…
            </div>
          )}
          {processedRows.map((row, i) => (
            <div key={i} className={`flex items-center gap-3 px-4 py-2.5 text-xs transition-colors ${
              row.status === 'issued' ? 'hover:bg-green-50/50 dark:hover:bg-green-900/10' : 'hover:bg-red-50/50 dark:hover:bg-red-900/10'
            }`}>
              {row.status === 'issued'
                ? <CheckCircle2 className="h-3.5 w-3.5 text-green-500 shrink-0" />
                : <XCircle     className="h-3.5 w-3.5 text-red-400  shrink-0" />}
              <span className="font-mono text-foreground w-36 truncate shrink-0">{row.member_identifier}</span>
              {row.status === 'issued'
                ? <span className="text-green-600 dark:text-green-400 font-medium">Issued</span>
                : <span className="text-red-500 truncate">{row.reason}</span>}
              <span className="ml-auto text-muted-foreground shrink-0">{row.ms}ms</span>
            </div>
          ))}
          {isRunning && rows[done] && (
            <div className="flex items-center gap-3 px-4 py-2.5 text-xs bg-muted/30">
              <Loader2 className="h-3.5 w-3.5 animate-spin text-primary shrink-0" />
              <span className="font-mono text-muted-foreground">{rows[done]?.member_identifier}</span>
              <span className="text-muted-foreground">Verifying…</span>
            </div>
          )}
        </div>
      </div>

      {/* Failure export */}
      {finished && failed > 0 && (
        <div className="card p-4 space-y-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-4 w-4 text-red-500" />
              <span className="text-sm font-semibold text-foreground">{failed} Failed Record{failed !== 1 ? 's' : ''}</span>
            </div>
            <button
              onClick={() => {
                const failedRows = processedRows.filter(r => r.status === 'failed');
                const csv = `member_identifier,reason\n${failedRows.map(r => `${r.member_identifier},${r.reason}`).join('\n')}`;
                downloadCsv(csv, `failed_${template?.name?.replace(/\s+/g, '_') || 'bulk'}.csv`);
              }}
              className="text-xs text-primary hover:underline flex items-center gap-1"
            >
              <Download className="h-3 w-3" /> Export failures
            </button>
          </div>
        </div>
      )}

      {/* Actions */}
      {finished && (
        <div className="flex gap-3">
          <Button variant="outline" onClick={onReset} className="flex-1">
            <RefreshCw className="h-4 w-4 mr-1" /> New Batch
          </Button>
          {issued > 0 && (
            <Button onClick={() => navigate('/issuer/issued')} className="flex-grow">
              View Issued Credentials <ChevronRight className="h-4 w-4 ml-1" />
            </Button>
          )}
        </div>
      )}
    </div>
  );
}

// ── Main Component ─────────────────────────────────────────────────────────

export default function BulkIssuancePage() {
  const [step, setStep] = useState(STEP_SELECT);

  // Template
  const [templates, setTemplates]               = useState([]);
  const [selectedTemplateId, setSelectedTemplateId] = useState('');
  const [selectedTemplate, setSelectedTemplate] = useState(null);
  const [loadingTemplate, setLoadingTemplate]   = useState(false);

  // Upload
  const [file, setFile]     = useState(null);
  const [parsed, setParsed] = useState(null);

  // Processing
  const [processedRows, setProcessedRows] = useState([]);
  const [isRunning, setIsRunning]         = useState(false);
  const abortRef = useRef(false);

  useEffect(() => {
    getTemplates({ is_active: true })
      .then(r => setTemplates(r.data?.results || r.data || []))
      .catch(() => {});
  }, []);

  useEffect(() => {
    if (!selectedTemplateId) { setSelectedTemplate(null); return; }
    setLoadingTemplate(true);
    getTemplate(selectedTemplateId)
      .then(r => setSelectedTemplate(r.data))
      .catch(() => {})
      .finally(() => setLoadingTemplate(false));
  }, [selectedTemplateId]);

  // ── Core: process rows one-by-one ────────────────────────────────────────

  const startProcessing = useCallback(async () => {
    const rows = parsed?.rows || [];
    if (!rows.length || !selectedTemplateId) return;

    setStep(STEP_PROCESS);
    setProcessedRows([]);
    setIsRunning(true);
    abortRef.current = false;

    const manualFields = (selectedTemplate?.fields || []).filter(f => f.source === 'manual');

    for (let i = 0; i < rows.length; i++) {
      if (abortRef.current) break;

      const row = rows[i];
      const memberId = row['member_identifier']?.trim();
      const t0 = Date.now();

      // Build manual claims from remaining columns
      const manualClaims = {};
      for (const f of manualFields) {
        if (row[f.name] !== undefined && row[f.name] !== '') {
          manualClaims[f.name] = row[f.name];
        }
      }

      try {
        await issueCredential({
          template_id: selectedTemplateId,
          member_identifier: memberId,
          manual_claims: manualClaims,
        });
        setProcessedRows(prev => [...prev, {
          member_identifier: memberId,
          status: 'issued',
          reason: '',
          ms: Date.now() - t0,
        }]);
      } catch (err) {
        const msg = err.response?.data?.error || err.response?.data?.detail || 'Issuance failed';
        setProcessedRows(prev => [...prev, {
          member_identifier: memberId,
          status: 'failed',
          reason: friendlyReason(msg),
          ms: Date.now() - t0,
        }]);
      }
    }

    setIsRunning(false);
  }, [parsed, selectedTemplateId, selectedTemplate]);

  const handleReset = () => {
    setStep(STEP_SELECT);
    setFile(null);
    setParsed(null);
    setProcessedRows([]);
    setSelectedTemplateId('');
    setSelectedTemplate(null);
    abortRef.current = false;
  };

  return (
    <div className="max-w-2xl space-y-2">
      <div className="mb-2">
        <h1 className="text-2xl font-bold text-foreground">Bulk Issuance</h1>
        <p className="text-sm text-muted-foreground mt-1">
          Issue credentials to multiple recipients with a real-time progress feed.
        </p>
      </div>

      <StepBar current={step} />

      <div className="card p-6">
        {step === STEP_SELECT && (
          <Step1Template
            templates={templates}
            selectedId={selectedTemplateId}
            setSelectedId={setSelectedTemplateId}
            selectedTemplate={selectedTemplate}
            loadingTemplate={loadingTemplate}
            onNext={() => setStep(STEP_UPLOAD)}
          />
        )}
        {step === STEP_UPLOAD && (
          <Step2Upload
            template={selectedTemplate}
            file={file}
            setFile={setFile}
            parsed={parsed}
            setParsed={setParsed}
            onNext={() => setStep(STEP_REVIEW)}
            onBack={() => setStep(STEP_SELECT)}
          />
        )}
        {step === STEP_REVIEW && (
          <Step3Review
            template={selectedTemplate}
            parsed={parsed}
            file={file}
            onStart={startProcessing}
            onBack={() => setStep(STEP_UPLOAD)}
          />
        )}
        {step === STEP_PROCESS && (
          <Step4Processing
            rows={parsed?.rows || []}
            template={selectedTemplate}
            processedRows={processedRows}
            isRunning={isRunning}
            abortRef={abortRef}
            onReset={handleReset}
          />
        )}
      </div>
    </div>
  );
}

