    36→
    37→  // Clear processed actions & save timestamp
    38→  await clearProcessedActions(response.processed_actions.map(a => a.action_id));
    39→  await AsyncStorage.setItem(KEYS.LAST_SYNC, response.sync_timestamp);
    40→
    41→  return response;
    42→}
    43→
    44→export async function addOfflineAction(type: string, data: unknown): Promise<void> {
    45→  const action: OfflineAction = {
    46→    id: `action-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    47→    type, data, timestamp: new Date().toISOString(),
    48→  };
    49→  const queue = await getOfflineActions();
    50→  queue.push(action);
    51→  await AsyncStorage.setItem(KEYS.OFFLINE_QUEUE, JSON.stringify(queue));
    52→}
    53→
    54→export async function getOfflineActions(): Promise<OfflineAction[]> {
    55→  const json = await AsyncStorage.getItem(KEYS.OFFLINE_QUEUE);
    56→  return json ? JSON.parse(json) : [];
    57→}
    58→
    59→export async function clearSyncData(): Promise<void> {
    60→  await AsyncStorage.multiRemove([KEYS.SYNC_TOKEN, KEYS.LAST_SYNC, KEYS.OFFLINE_QUEUE]);
    61→}
    62→
    63→async function clearProcessedActions(ids: string[]): Promise<void> {
    64→  const queue = await getOfflineActions();
    65→  await AsyncStorage.setItem(KEYS.OFFLINE_QUEUE, JSON.stringify(queue.filter(a => !ids.includes(a.id))));
    66→}
