/**
 * tokenManager.ts
 * Proactively refreshes the JWT access token before it expires.
 * — Decodes JWT locally (no server round-trip) to check expiry
 * — Schedules a timer to refresh 5 min before expiry
 * — On network reconnect, immediately checks and refreshes if within window
 * — Offline tokens (prefixed "offline-") are skipped gracefully
 */
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';
import { authApi } from './authApi';

const REFRESH_AHEAD_MS = 5 * 60 * 1000;   // refresh 5 min before expiry
const OFFLINE_PREFIX   = 'offline-';
const KEY_ACCESS       = 'access_token';
const KEY_REFRESH      = 'refresh_token';
const KEY_ACCESS_BAK   = 'backup_access_token';
const KEY_REFRESH_BAK  = 'backup_refresh_token';

let refreshTimer: ReturnType<typeof setTimeout> | null = null;
let isRefreshing = false;

// ── JWT helpers (no verification — local decode only) ─────────────────────────

export function decodeJwtPayload(token: string): Record<string, unknown> | null {
  try {
    const parts = token.split('.');
    if (parts.length !== 3) return null;
    const base64 = parts[1].replace(/-/g, '+').replace(/_/g, '/');
    const padded  = base64 + '='.repeat((4 - (base64.length % 4)) % 4);
    return JSON.parse(atob(padded)) as Record<string, unknown>;
  } catch {
    return null;
  }
}

export function getTokenExpiryMs(token: string): number | null {
  const p = decodeJwtPayload(token);
  return p && typeof p.exp === 'number' ? p.exp * 1000 : null;
}

export function isTokenExpired(token: string): boolean {
  const exp = getTokenExpiryMs(token);
  return exp == null || Date.now() >= exp;
}

export function msUntilExpiry(token: string): number {
  const exp = getTokenExpiryMs(token);
  return exp == null ? -1 : exp - Date.now();
}

// ── Storage helpers ───────────────────────────────────────────────────────────

async function readAccessToken(): Promise<string | null> {
  try {
    return (
      (await SecureStore.getItemAsync(KEY_ACCESS)) ??
      (await AsyncStorage.getItem(KEY_ACCESS_BAK))
    );
  } catch {
    return null;
  }
}

async function readRefreshToken(): Promise<string | null> {
  try {
    return (
      (await SecureStore.getItemAsync(KEY_REFRESH)) ??
      (await AsyncStorage.getItem(KEY_REFRESH_BAK))
    );
  } catch {
    return null;
  }
}

async function persistTokens(access: string, refresh?: string): Promise<void> {
  await Promise.all([
    SecureStore.setItemAsync(KEY_ACCESS, access).catch(() => {}),
    AsyncStorage.setItem(KEY_ACCESS_BAK, access),
  ]);
  if (refresh) {
    await Promise.all([
      SecureStore.setItemAsync(KEY_REFRESH, refresh).catch(() => {}),
      AsyncStorage.setItem(KEY_REFRESH_BAK, refresh),
    ]);
  }
}

// ── Core refresh ──────────────────────────────────────────────────────────────

async function performRefresh(): Promise<boolean> {
  if (isRefreshing) return false;
  isRefreshing = true;
  try {
    const refreshToken = await readRefreshToken();
    if (!refreshToken) { isRefreshing = false; return false; }

    // Offline tokens — never attempt server refresh
    if (refreshToken.startsWith(OFFLINE_PREFIX)) {
      isRefreshing = false;
      return false;
    }

    const response = await authApi.refreshToken(refreshToken);
    if (!response?.access) { isRefreshing = false; return false; }

    await persistTokens(response.access, response.refresh);
    scheduleRefresh(response.access);
    isRefreshing = false;
    return true;
  } catch {
    // Network unavailable — silent fail; app continues with cached data
    isRefreshing = false;
    return false;
  }
}

// ── Scheduler ─────────────────────────────────────────────────────────────────

function scheduleRefresh(token: string): void {
  if (refreshTimer) clearTimeout(refreshTimer);
  const remaining = msUntilExpiry(token);
  if (remaining <= 0) {
    performRefresh().catch(() => {});
    return;
  }
  const delay = Math.max(0, remaining - REFRESH_AHEAD_MS);
  refreshTimer = setTimeout(() => { performRefresh().catch(() => {}); }, delay);
}

// ── Public API ────────────────────────────────────────────────────────────────

/**
 * Start the manager. Call once after successful local authentication.
 * Reads the stored access token, decides whether to refresh now or schedule.
 */
export async function startTokenManager(): Promise<void> {
  const token = await readAccessToken();
  if (!token || token.startsWith(OFFLINE_PREFIX)) return;

  if (isTokenExpired(token)) {
    await performRefresh();
  } else {
    scheduleRefresh(token);
  }
}

/**
 * Stop the manager — call on logout or app unmount.
 */
export function stopTokenManager(): void {
  if (refreshTimer) { clearTimeout(refreshTimer); refreshTimer = null; }
  isRefreshing = false;
}

/**
 * Called when network connectivity is restored.
 * Immediately refreshes if the token is stale or about to expire,
 * then reschedules the timer.
 */
export async function onNetworkReconnect(): Promise<void> {
  const token = await readAccessToken();
  if (!token || token.startsWith(OFFLINE_PREFIX)) return;

  const remaining = msUntilExpiry(token);
  if (remaining <= REFRESH_AHEAD_MS) {
    await performRefresh();
  } else {
    scheduleRefresh(token); // ensure timer is set after reconnect
  }
}

/**
 * Snapshot of the current token state — useful for displaying
 * connection/session status in the UI.
 */
export async function getTokenStatus(): Promise<{
  hasToken: boolean;
  isExpired: boolean;
  isOfflineToken: boolean;
  expiresInMs: number | null;
  expiresAt: Date | null;
}> {
  const token = await readAccessToken();
  if (!token) {
    return { hasToken: false, isExpired: true, isOfflineToken: false, expiresInMs: null, expiresAt: null };
  }
  if (token.startsWith(OFFLINE_PREFIX)) {
    return { hasToken: true, isExpired: false, isOfflineToken: true, expiresInMs: null, expiresAt: null };
  }
  const expMs = getTokenExpiryMs(token);
  return {
    hasToken: true,
    isExpired: isTokenExpired(token),
    isOfflineToken: false,
    expiresInMs: expMs != null ? expMs - Date.now() : null,
    expiresAt: expMs != null ? new Date(expMs) : null,
  };
}

/**
 * useNetworkStatus.ts
 * Detects network connectivity without requiring @react-native-community/netinfo.
 * Strategy:
 *  1. Check navigator.onLine (fast, no I/O)
 *  2. Confirm with a lightweight HTTP probe to dns.google
 *  3. Poll every 15 s + re-check whenever the app comes to the foreground
 *  4. Fire onReconnect() (debounced) on any offline → online transition
 */
import { useState, useEffect, useRef, useCallback } from 'react';
import { AppState, AppStateStatus } from 'react-native';

const PING_URL        = 'https://dns.google/generate_204';
const PING_TIMEOUT_MS = 4000;
const POLL_INTERVAL_MS = 15000;
const DEBOUNCE_MS     = 800;

async function checkConnectivity(): Promise<boolean> {
  try {
    if (typeof navigator !== 'undefined' && 'onLine' in navigator && !navigator.onLine) {
      return false;
    }
    const ctrl  = new AbortController();
    const timer = setTimeout(() => ctrl.abort(), PING_TIMEOUT_MS);
    const res   = await fetch(PING_URL, { method: 'HEAD', signal: ctrl.signal });
    clearTimeout(timer);
    return res.status === 204 || res.ok;
  } catch {
    return false;
  }
}

export interface NetworkStatus {
  isOnline: boolean;
  isChecking: boolean;
  lastCheckedAt: Date | null;
  checkNow: () => Promise<void>;
}

export function useNetworkStatus(onReconnect?: () => void): NetworkStatus {
  const [isOnline,      setIsOnline]      = useState(true);  // optimistic
  const [isChecking,    setIsChecking]    = useState(false);
  const [lastCheckedAt, setLastCheckedAt] = useState<Date | null>(null);

  const wasOnlineRef     = useRef(true);
  const debounceRef      = useRef<ReturnType<typeof setTimeout> | null>(null);
  const pollRef          = useRef<ReturnType<typeof setInterval> | null>(null);
  const onReconnectRef   = useRef(onReconnect);
  const isMountedRef     = useRef(true);

  useEffect(() => { onReconnectRef.current = onReconnect; }, [onReconnect]);

  const check = useCallback(async () => {
    if (!isMountedRef.current) return;
    setIsChecking(true);
    const online = await checkConnectivity();
    if (!isMountedRef.current) return;

    setIsOnline(online);
    setLastCheckedAt(new Date());
    setIsChecking(false);

    // offline → online transition
    if (online && !wasOnlineRef.current) {
      if (debounceRef.current) clearTimeout(debounceRef.current);
      debounceRef.current = setTimeout(() => {
        onReconnectRef.current?.();
      }, DEBOUNCE_MS);
    }
    wasOnlineRef.current = online;
  }, []);

  useEffect(() => {
    isMountedRef.current = true;
    check();

    pollRef.current = setInterval(check, POLL_INTERVAL_MS);

    const appSub = AppState.addEventListener('change', (state: AppStateStatus) => {
      if (state === 'active') check();
    });

    return () => {
      isMountedRef.current = false;
      if (pollRef.current)   clearInterval(pollRef.current);
      if (debounceRef.current) clearTimeout(debounceRef.current);
      appSub.remove();
    };
  }, [check]);

  return { isOnline, isChecking, lastCheckedAt, checkNow: check };
}

import type { ApiConfig } from './config';
import type { ApiErrorResponse } from './types';

export class ApiError extends Error {
  constructor(
    message: string,
    public readonly status: number,
    public readonly body?: ApiErrorResponse,
  ) {
    super(message);
    this.name = 'ApiError';
  }
}

export class ApiClient {
  private config: ApiConfig;
  private tokenRefresher: (() => Promise<string | null>) | null = null;

  constructor(config: ApiConfig) {
    this.config = config;
  }

  getConfig(): ApiConfig { return { ...this.config }; }
  setBaseUrl(url: string): void { this.config.baseUrl = url; }

  /**
   * Register a callback that returns a fresh access token.
   * When a 401 is received the client will call this once and retry.
   */
  setTokenRefresher(fn: () => Promise<string | null>): void {
    this.tokenRefresher = fn;
  }

  async get<T>(path: string, token?: string): Promise<T> {
    return this.request<T>(path, 'GET', undefined, token);
  }
  async post<T>(path: string, body?: unknown, token?: string): Promise<T> {
    return this.request<T>(path, 'POST', body, token);
  }
  async put<T>(path: string, body?: unknown, token?: string): Promise<T> {
    return this.request<T>(path, 'PUT', body, token);
  }
  async patch<T>(path: string, body?: unknown, token?: string): Promise<T> {
    return this.request<T>(path, 'PATCH', body, token);
  }
  async delete<T>(path: string, token?: string): Promise<T> {
    return this.request<T>(path, 'DELETE', undefined, token);
  }
  async postFormData<T>(path: string, formData: FormData, token?: string): Promise<T> {
    return this.requestFormData<T>(path, 'POST', formData, token);
  }

  private buildUrl(path: string): string {
    const base = this.config.baseUrl.endsWith('/')
      ? this.config.baseUrl.slice(0, -1)
      : this.config.baseUrl;
    return `${base}${path.startsWith('/') ? path : `/${path}`}`;
  }

  private async request<T>(
    path: string,
    method: string,
    body?: unknown,
    token?: string,
    timeoutMs = 30000,
    _isRetry = false,
  ): Promise<T> {
    const headers: Record<string, string> = {
      Accept: 'application/json',
      'Content-Type': 'application/json',
    };
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const url = this.buildUrl(path);
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    let res: Response;
    try {
      res = await fetch(url, {
        method,
        headers,
        body: body != null ? JSON.stringify(body) : undefined,
        signal: controller.signal,
      });
      clearTimeout(timer);
    } catch (err) {
      clearTimeout(timer);
      if (err instanceof ApiError) throw err;
      if (err instanceof Error && err.name === 'AbortError') {
        throw new ApiError('Request timed out.', -2);
      }
      const isNetwork =
        err instanceof TypeError &&
        (err.message.includes('Network request failed') ||
          err.message.includes('Failed to fetch') ||
          err.message.includes('NetworkError'));
      const connErr = new ApiError(
        isNetwork
          ? 'Connection failed. Server unreachable or no internet.'
          : 'Connection failed. Check your internet connection.',
        -1,
      );
      if (isNetwork) connErr.name = 'ConnectionError';
      throw connErr;
    }

    // ── 401 auto-refresh ──────────────────────────────────────────────────────
    if (res.status === 401 && !_isRetry && this.tokenRefresher) {
      try {
        const freshToken = await this.tokenRefresher();
        if (freshToken) {
          // Retry the original request once with the refreshed token
          return this.request<T>(path, method, body, freshToken, timeoutMs, true);
        }
      } catch {
        // Refresh failed — fall through to throw the original 401
      }
    }

    const isJson = (res.headers.get('content-type') ?? '').includes('application/json');
    const payload: unknown = isJson ? await res.json() : { detail: await res.text() };

    if (!res.ok) {
      let msg = 'Request failed';
      if (payload && typeof payload === 'object') {
        const p = payload as Record<string, unknown>;
        msg = String(p.detail ?? p.message ?? p.error ?? msg);
      }
      throw new ApiError(msg, res.status, payload as ApiErrorResponse);
    }
    return payload as T;
  }

  private async requestFormData<T>(
    path: string,
    method: string,
    formData: FormData,
    token?: string,
  ): Promise<T> {
    const headers: Record<string, string> = { Accept: 'application/json' };
    if (token) headers['Authorization'] = `Bearer ${token}`;

    const url = this.buildUrl(path);
    const res = await fetch(url, { method, headers, body: formData });
    const isJson = (res.headers.get('content-type') ?? '').includes('application/json');
    const payload: unknown = isJson ? await res.json() : { detail: await res.text() };

    if (!res.ok) {
      let msg = 'Request failed';
      if (payload && typeof payload === 'object') {
        const p = payload as Record<string, unknown>;
        msg = String(p.detail ?? p.message ?? p.error ?? msg);
      }
      throw new ApiError(msg, res.status, payload as ApiErrorResponse);
    }
    return payload as T;
  }
}

import { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import {
  getIssuerRequests, approveRequest, rejectRequest,
  bulkApproveRequests, bulkRejectRequests,
} from '../../api/issuer';
import Table from '../../components/common/Table';
import { StatusBadge } from '../../components/common/Badge';
import Button from '../../components/common/Button';
import Select from '../../components/common/Select';
import Modal from '../../components/common/Modal';
import Input from '../../components/common/Input';
import { formatDate, formatRelative } from '../../utils/formatDate';
import toast from 'react-hot-toast';
import {
  CheckCircle2, XCircle, Bell, RefreshCw,
  Clock, FileCheck2, FileX2, Eye,
} from 'lucide-react';

const POLL_MS = 30_000;

export default function RequestsPage() {
  const [requests,     setRequests]     = useState([]);
  const [loading,      setLoading]      = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [selected,     setSelected]     = useState([]);
  const [rejectModal,  setRejectModal]  = useState(null);
  const [rejectReason, setRejectReason] = useState('');
  const [actioning,    setActioning]    = useState(false);
  const [lastLoaded,   setLastLoaded]   = useState(null);
  const [newCount,     setNewCount]     = useState(0);
  const prevPendingRef = useRef(0);
  const pollRef        = useRef(null);

  const load = async (silent = false) => {
    if (!silent) setLoading(true);
    try {
      const params = {};
      if (statusFilter) params.status = statusFilter;
      const r = await getIssuerRequests(params);
      const list = r.data?.results || r.data || [];
      setRequests(list);
      setLastLoaded(new Date());
      // Badge: count new pending arrivals since last load
      const pending = list.filter(x => x.status === 'pending').length;
      if (!silent) { prevPendingRef.current = pending; }
      else {
        const diff = pending - prevPendingRef.current;
        if (diff > 0) setNewCount(diff);
        prevPendingRef.current = pending;
      }
    } catch { /* silent */ }
    finally { if (!silent) setLoading(false); }
  };

  useEffect(() => {
    load();
    setSelected([]);
    prevPendingRef.current = 0;
    setNewCount(0);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter]);

  // Background polling
  useEffect(() => {
    pollRef.current = setInterval(() => load(true), POLL_MS);
    return () => clearInterval(pollRef.current);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [statusFilter]);

  const pending  = requests.filter(r => r.status === 'pending').length;
  const approved = requests.filter(r => r.status === 'approved' || r.status === 'issued').length;
  const rejected = requests.filter(r => r.status === 'rejected').length;

  const handleApprove = async (id) => {
    try {
      await approveRequest(id);
      toast.success('Request approved — credential issued');
      load();
    } catch (err) {
      toast.error(err.response?.data?.error || err.response?.data?.detail || 'Approval failed');
    }
  };

  const handleReject = async () => {
    if (!rejectReason.trim()) { toast.error('Reason is required'); return; }
    setActioning(true);
    try {
      await rejectRequest(rejectModal, { reason: rejectReason });
      toast.success('Request rejected');
      setRejectModal(null);
      setRejectReason('');
      load();
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Rejection failed');
    } finally { setActioning(false); }
  };

  const bulkApprove = async () => {
    if (!selected.length) return;
    try {
      const res = await bulkApproveRequests({ request_ids: selected });
      toast.success(`${res.data.approved?.length || 0} approved`);
      if (res.data.failed?.length) toast.error(`${res.data.failed.length} failed`);
      setSelected([]);
      load();
    } catch { toast.error('Bulk approve failed'); }
  };

  const bulkReject = async () => {
    if (!selected.length) return;
    try {
      await bulkRejectRequests({ request_ids: selected, reason: 'Bulk rejected' });
      toast.success(`${selected.length} rejected`);
      setSelected([]);
      load();
    } catch { toast.error('Bulk reject failed'); }
  };

  const toggleSelect = (id) => {
    setSelected(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  const columns = [
    {
      key: 'select', label: '',
      render: (_, row) => row.status === 'pending' ? (
        <input
          type="checkbox"
          checked={selected.includes(row.id)}
          onChange={() => toggleSelect(row.id)}
          className="rounded border-border"
        />
      ) : null,
    },
    {
      key: 'holder_name', label: 'Holder',
      render: (v, row) => (
        <div>
          <p className="font-medium text-foreground">{v || row.holder_email || '—'}</p>
          {row.holder_national_id && (
            <p className="text-xs text-muted-foreground font-mono">{row.holder_national_id}</p>
          )}
        </div>
      ),
    },
    { key: 'credential_type_name', label: 'Credential Type', render: (v, row) => v || row.credential_type || '—' },
    {
      key: 'status', label: 'Status',
      render: (v) => <StatusBadge status={v} />,
    },
    {
      key: 'created_at', label: 'Requested',
      render: (v) => (
        <span className="text-sm text-muted-foreground">{formatRelative ? formatRelative(v) : formatDate(v)}</span>
      ),
    },
    {
      key: 'actions', label: '',
      render: (_, row) => (
        <div className="flex items-center gap-1">
          <Link to={`/issuer/requests/${row.id}`}>
            <Button size="sm" variant="ghost" className="gap-1">
              <Eye className="h-3.5 w-3.5" />View
            </Button>
          </Link>
          {row.status === 'pending' && (
            <>
              <Button
                size="sm" variant="outline"
                className="text-green-600 border-green-200 hover:bg-green-50 gap-1"
                onClick={() => handleApprove(row.id)}
              >
                <CheckCircle2 className="h-3.5 w-3.5" />Approve
              </Button>
              <Button
                size="sm" variant="outline"
                className="text-red-500 border-red-200 hover:bg-red-50 gap-1"
                onClick={() => { setRejectModal(row.id); setRejectReason(''); }}
              >
                <XCircle className="h-3.5 w-3.5" />Reject
              </Button>
            </>
          )}
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-start justify-between gap-4">
        <div>
          <div className="flex items-center gap-2">
            <h1 className="text-2xl font-bold text-foreground">Credential Requests</h1>
            {newCount > 0 && (
              <span className="inline-flex items-center gap-1 rounded-full bg-primary px-2 py-0.5 text-xs font-bold text-primary-foreground animate-pulse">
                <Bell className="h-3 w-3" />{newCount} new
              </span>
            )}
          </div>
          <p className="text-muted-foreground text-sm mt-1">
            Review and respond to holder requests.
            {lastLoaded && (
              <span className="ml-2 text-xs text-muted-foreground/60">
                Updated {formatRelative ? formatRelative(lastLoaded.toISOString()) : 'just now'}
              </span>
            )}
          </p>
        </div>

        <div className="flex items-center gap-2">
          {selected.length > 0 && (
            <>
              <Button size="sm" variant="outline" className="text-green-600 border-green-200" onClick={bulkApprove}>
                <CheckCircle2 className="h-3.5 w-3.5" />Approve {selected.length}
              </Button>
              <Button size="sm" variant="outline" className="text-red-500 border-red-200" onClick={bulkReject}>
                <XCircle className="h-3.5 w-3.5" />Reject {selected.length}
              </Button>
            </>
          )}
          <Button
            size="sm" variant="outline"
            onClick={() => { setNewCount(0); load(); }}
            className="gap-1.5"
          >
            <RefreshCw className="h-3.5 w-3.5" />Refresh
          </Button>
        </div>
      </div>

      {/* Stats */}
      {!loading && (
        <div className="grid grid-cols-3 gap-4">
          <div className="rounded-xl border border-border bg-card p-4 flex items-center gap-3">
            <div className="rounded-lg bg-yellow-100 dark:bg-yellow-900/30 p-2">
              <Clock className="h-4 w-4 text-yellow-600 dark:text-yellow-400" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{pending}</p>
              <p className="text-xs text-muted-foreground">Pending</p>
            </div>
          </div>
          <div className="rounded-xl border border-border bg-card p-4 flex items-center gap-3">
            <div className="rounded-lg bg-green-100 dark:bg-green-900/30 p-2">
              <FileCheck2 className="h-4 w-4 text-green-600 dark:text-green-400" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{approved}</p>
              <p className="text-xs text-muted-foreground">Approved / Issued</p>
            </div>
          </div>
          <div className="rounded-xl border border-border bg-card p-4 flex items-center gap-3">
            <div className="rounded-lg bg-red-100 dark:bg-red-900/30 p-2">
              <FileX2 className="h-4 w-4 text-red-600 dark:text-red-400" />
            </div>
            <div>
              <p className="text-2xl font-bold text-foreground">{rejected}</p>
              <p className="text-xs text-muted-foreground">Rejected</p>
            </div>
          </div>
        </div>
      )}

      {/* Filter */}
      <div className="flex items-center gap-3">
        <Select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
          className="w-48"
        >
          <option value="">All statuses</option>
          <option value="pending">Pending</option>
          <option value="approved">Approved</option>
          <option value="issued">Issued</option>
          <option value="rejected">Rejected</option>
        </Select>
      </div>

      {/* Table */}
      <Table
        columns={columns}
        data={requests}
        loading={loading}
        emptyMessage="No requests found."
      />

      {/* Reject modal */}
      <Modal
        isOpen={!!rejectModal}
        onClose={() => { setRejectModal(null); setRejectReason(''); }}
        title="Reject Request"
      >
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Provide a reason so the holder understands why their request was declined.
          </p>
          <Input
            label="Reason for rejection"
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            placeholder="e.g. Identity could not be verified…"
          />
          <div className="flex gap-3">
            <Button variant="outline" className="flex-1" onClick={() => setRejectModal(null)}>
              Cancel
            </Button>
            <Button
              className="flex-1 bg-red-500 hover:bg-red-600 text-white"
              isLoading={actioning}
              onClick={handleReject}
            >
              <XCircle className="h-4 w-4" />Reject
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}

import { useEffect, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import {
