// ── Token management ─────────────────────────────────────────────────────────

/**
 * Force-refresh the access token regardless of whether one already exists.
 * Called automatically by ApiClient on 401 responses.
 * Returns the new access token, or null if offline / refresh token missing.
 */
export async function forceRefreshToken(): Promise<string | null> {
  const refreshToken =
    (await SecureStore.getItemAsync(KEYS.REFRESH_TOKEN)) ??
    (await AsyncStorage.getItem('backup_refresh_token'));

  if (!refreshToken) return null;

  // Offline tokens — never attempt server refresh
  if (refreshToken.startsWith('offline-')) return null;

  try {
    const response = await authApi.refreshToken(refreshToken);
    if (!response?.access) return null;

    await SecureStore.setItemAsync(KEYS.ACCESS_TOKEN, response.access);
    await AsyncStorage.setItem('backup_access_token', response.access);
    if (response.refresh) {
      await SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, response.refresh);
      await AsyncStorage.setItem('backup_refresh_token', response.refresh);
    }
    return response.access;
  } catch {
    return null;
  }
}

