import AsyncStorage from '@react-native-async-storage/async-storage';
import React, { createContext, useCallback, useContext, useEffect, useMemo, useRef, useState } from 'react';

import {
  authenticateLocally, getAuthStatus, getStoredDID, getStoredUser,
  logout as holderLogout, registerWithServer, requestOTP as holderRequestOTP,
  requestOTPForPINReset, resetAllData, resetPINWithOTP, setupLocalAuthentication,
  type HolderUser,
} from '@/services/auth/holderAuth';
import { authApi } from '@/services/auth/authApi';
import { credentialApi } from '@/services/credentials/credentialApi';
import { nidApi } from '@/services/nid/nidApi';
import * as LocalAuth from '@/services/auth/localAuth';
import { startTokenManager, stopTokenManager, onNetworkReconnect } from '@/services/auth/tokenManager';
import { syncData } from '@/services/sync/syncService';
import { useNetworkStatus } from '@/hooks/useNetworkStatus';
import { type MockCitizen, type MockCredential, type MockActivity, MOCK_CITIZENS } from '@/services/mockData';

export type { MockCitizen, MockCredential, MockActivity };

export interface Activity {
  id: string; action: string; actionType: string; credentialId?: string;
  credentialType?: string; issuerName?: string; timestamp: string; details?: string;
}

export interface PendingCitizen {
  nationalId: string; fullName: string; phone: string; maskedPhone: string;
  gender: string; dob: string; region: string; city: string;
  nationality: string; did: string; photo?: string;
}

// ── Mappers ───────────────────────────────────────────────────────────────────

const CRED_COLORS: Record<string, string> = {
  EDUCATION: '#1B6B3A', AcademicDegree: '#1B6B3A', GOVERNMENT: '#C8991A',
  NationalId: '#C8991A', HEALTH: '#C0392B', PROFESSIONAL: '#7B3FA0', EMPLOYMENT: '#B45309',
};
const CRED_ICONS: Record<string, string> = {
  EDUCATION: 'school', AcademicDegree: 'school', GOVERNMENT: 'card',
  NationalId: 'card', HEALTH: 'medkit', PROFESSIONAL: 'ribbon', EMPLOYMENT: 'briefcase',
};
const SECTORS = ['EDUCATION','GOVERNMENT','HEALTH','PROFESSIONAL','EMPLOYMENT','FINANCE'] as const;
type Sector = typeof SECTORS[number];
const toSector = (s: string): Sector =>
  (SECTORS.includes(s as Sector) ? s : 'EDUCATION') as Sector;

function toCredential(c: Record<string, unknown>): MockCredential {
  const rawType = String(c.credential_type_name ?? c.type ?? '');
  const typeKey = rawType.replace(/Credential$/, '');
  const claims = (c.claims ?? c.credentialSubject ?? {}) as Record<string, string>;
  const statusRaw = String(c.status ?? 'active').toUpperCase();
  const issuerObj = (c.issuer && typeof c.issuer === 'object') ? (c.issuer as Record<string, unknown>) : null;
  return {
    id: String(c.credential_uuid ?? c.id ?? ''),
    type: rawType,
    title: String(claims.title ?? claims.degreeType ?? claims.certificationName ?? typeKey),
    subtitle: String(claims.subtitle ?? claims.degreeField ?? claims.jobTitle ?? c.organization_name ?? ''),
    issuer: {
      did: String(c.issuer_did ?? issuerObj?.did ?? ''),
      name: String(c.organization_name ?? c.issuer_name ?? issuerObj?.name ?? ''),
      sector: toSector(String(issuerObj?.sector ?? typeKey)),
    },
    issuanceDate: String(c.issued_at ?? c.issuance_date ?? ''),
    expiryDate: c.expires_at ? String(c.expires_at) : null,
    status: (['ACTIVE','REVOKED','EXPIRED','SUSPENDED'].includes(statusRaw) ? statusRaw : 'ACTIVE') as MockCredential['status'],
    holderDid: String(c.holder_did ?? ''),
    credentialSubject: claims,
    proofFormat: 'DATA_INTEGRITY',
    verificationUrl: String(c.verification_url ?? ''),
    ebcsAnchored: Boolean(c.ebcs_anchored ?? false),
    ebcsTxId: String(c.ebcs_tx_id ?? ''),
    color: CRED_COLORS[rawType] ?? CRED_COLORS[typeKey] ?? '#1B6B3A',
    icon: CRED_ICONS[rawType] ?? CRED_ICONS[typeKey] ?? 'document-text',
  };
}

const ACT_MAP: Record<string, MockActivity['type']> = {
  CREDENTIAL_ISSUED: 'ISSUED', CREDENTIAL_SHARED: 'SHARED',
  CREDENTIAL_VERIFIED: 'VERIFIED', AUTH_LOGIN: 'LOGIN',
  CREDENTIAL_RECEIVED: 'RECEIVED', CREDENTIAL_REVOKED: 'REVOKED',
};
function toActivity(a: Activity): MockActivity {
  return {
    id: a.id,
    type: ACT_MAP[a.actionType] ?? 'ISSUED',
    title: a.details ?? a.action,
    description: a.issuerName ?? a.credentialType ?? '',
    timestamp: a.timestamp,
    credentialId: a.credentialId,
  };
}

// ── Context type ──────────────────────────────────────────────────────────────

export interface SyncStatus {
  isSyncing: boolean;
  lastSyncAt: Date | null;
  syncError: string | null;
}

interface AuthContextType {
  isLoading: boolean; isOnboarded: boolean; isAuthenticated: boolean;
  biometricEnabled: boolean; biometricAvailable: boolean;
  user: HolderUser | null; citizen: MockCitizen | null; did: string | null;
  credentials: MockCredential[]; activities: MockActivity[];
  isLoadingCredentials: boolean; isLoadingActivities: boolean;
  language: string; theme: 'light' | 'dark' | 'system';
  pendingNationalId: string; pendingCitizen: PendingCitizen | null;
  pendingAccountExists: boolean;
  pendingPhone: string;
  pendingOtpForTesting?: string;
  /** Network connectivity state — updated every 15 s + on foreground */
  isOnline: boolean;
  /** Sync status for UI feedback */
  syncStatus: SyncStatus;
  setPendingPhone: (phone: string) => void;
  verifyNationalId: (id: string) => Promise<{ success: boolean; expiresIn: number; maskedPhone: string }>;
  verifyOtp: (otp: string, phone?: string) => Promise<void>;
  setPendingPin: (pin: string) => void;
  confirmPinAndSetup: (confirmPin: string) => Promise<boolean>;
  unlockWithPin: (pin: string) => Promise<boolean>;
  unlockWithBiometric: () => Promise<boolean>;
  logout: () => Promise<void>;
  deleteWallet: () => Promise<void>;
  setLanguage: (lang: string) => Promise<void>;
  setTheme: (t: 'light' | 'dark' | 'system') => Promise<void>;
  setupBiometric: () => Promise<boolean>;
  disableBiometric: () => Promise<void>;
  changePin: (oldPin: string, newPin: string) => Promise<void>;
  refreshCredentials: () => Promise<void>;
  refreshActivities: () => Promise<void>;
  addActivity: (a: Omit<Activity, 'id'>) => void;
  /** Manually trigger a full sync — credentials + profile. No-op if offline. */
  syncNow: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [isLoading, setIsLoading]             = useState(true);
  const [isOnboarded, setIsOnboarded]         = useState(false);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser]                       = useState<HolderUser | null>(null);
  const [did, setDid]                         = useState<string | null>(null);
  const [rawCredentials, setRawCredentials]   = useState<Record<string, unknown>[]>([]);
  const [rawActivities, setRawActivities]     = useState<Activity[]>([]);
  const [isLoadingCreds, setIsLoadingCreds]   = useState(false);
  const [isLoadingActs]                       = useState(false);
  const [language, setLangState]             = useState('en');
  const [theme, setThemeState]               = useState<'light'|'dark'|'system'>('system');
  const [pendingNationalId, setPendingNid]    = useState('');
  const [pendingCitizen, setPendingCitizen]   = useState<PendingCitizen | null>(null);
  const [pendingAccountExists, setPendingAccountExists] = useState(false);
  const [pendingPhone, setPendingPhone]       = useState('');
  const [pendingPin, setPendingPinState]      = useState('');
  const [pendingOtp, setPendingOtp]           = useState('');
  const [pendingOtpForTesting, setPendingOtpForTesting] = useState<string | undefined>(undefined);
  const [biometricEnabled, setBioEnabled]     = useState(false);
  const [biometricAvailable, setBioAvail]     = useState(false);
  const [syncStatus, setSyncStatus]           = useState<SyncStatus>({
    isSyncing: false, lastSyncAt: null, syncError: null,
  });

  // ── Network status — runs continuously, triggers sync+refresh on reconnect ──
  const handleReconnect = useCallback(() => {
    // When network comes back: refresh token + sync data
    onNetworkReconnect().catch(() => {});
    if (isAuthenticated) {
      setSyncStatus(s => ({ ...s, isSyncing: true, syncError: null }));
      syncData()
        .then(() => setSyncStatus({ isSyncing: false, lastSyncAt: new Date(), syncError: null }))
        .catch((e) => setSyncStatus(s => ({
          ...s, isSyncing: false,
          syncError: e instanceof Error ? e.message : 'Sync failed',
        })));
    }
  }, [isAuthenticated]);

  const { isOnline } = useNetworkStatus(handleReconnect);

  // ── Start/stop token manager when auth state changes ──────────────────────
  useEffect(() => {
    if (isAuthenticated) {
      startTokenManager().catch(() => {});
    } else {
      stopTokenManager();
    }
  }, [isAuthenticated]);

  // Derive MockCitizen from real HolderUser
  const citizen = useMemo<MockCitizen | null>(() => {
    if (!user) return null;
    const parts = (user.full_name ?? user.name ?? '').split(' ');
    return {
      nationalId: user.national_id, did: did ?? '',
      fullName: user.full_name ?? user.name ?? '',
      firstName: parts[0] ?? '', lastName: parts.slice(1).join(' '),
      gender: user.gender ?? '', dob: user.date_of_birth ?? '',
      phone: user.phone ?? '', email: '',
      region: String((user as unknown as Record<string,unknown>).region ?? ''),
      city: String((user as unknown as Record<string,unknown>).city ?? ''),
      photo: user.photo ?? '',
      walletAddress: `debo:${user.national_id}:wallet`,
      createdAt: new Date().toISOString(),
    };
  }, [user, did]);

  const credentials = useMemo(() => rawCredentials.map(toCredential), [rawCredentials]);
  const activities  = useMemo(() => rawActivities.map(toActivity),   [rawActivities]);

  // ── Bootstrap ─────────────────────────────────────────────────────────────
  useEffect(() => {
    (async () => {
      try {
        const [status, lang, th, bio] = await Promise.all([
          getAuthStatus(),
          AsyncStorage.getItem('language'),
          AsyncStorage.getItem('theme'),
          AsyncStorage.getItem('biometricEnabled'),
        ]);
        if (status.user) setUser(status.user as HolderUser);
        if (status.did)  setDid(status.did);
        setIsOnboarded(status.isRegistered);
        if (lang) setLangState(lang);
        if (th)   setThemeState(th as 'light'|'dark'|'system');
        setBioEnabled(bio === 'true');
        setBioAvail(await LocalAuth.isBiometricAvailable());
        if (status.isReady) {
          const ls = await LocalAuth.getLocalAuthStatus();
          if (ls.hasBiometric && ls.biometricAvailable) {
            const ok = await LocalAuth.authenticateWithBiometric();
            if (ok) { setIsAuthenticated(true); void loadCredentials(); }
          }
        }
      } catch (e) { console.warn('[AuthContext] bootstrap:', e); }
      finally { setIsLoading(false); }
    })();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const loadCredentials = useCallback(async () => {
    setIsLoadingCreds(true);
    try {
      const { credentials: list } = await credentialApi.listCredentials();
      setRawCredentials(list as Record<string, unknown>[]);
    } catch { /* offline — keep current state */ }
    finally { setIsLoadingCreds(false); }
  }, []);

  const loadActivities = useCallback(async () => {
    // Activities are populated locally via addActivity when actions occur
  }, []);

  // ── Manual sync ───────────────────────────────────────────────────────────
  const syncNow = useCallback(async () => {
    if (!isAuthenticated || !isOnline) return;
    setSyncStatus(s => ({ ...s, isSyncing: true, syncError: null }));
    try {
      await syncData();
      await loadCredentials();
      setSyncStatus({ isSyncing: false, lastSyncAt: new Date(), syncError: null });
    } catch (e) {
      setSyncStatus(s => ({
        ...s, isSyncing: false,
        syncError: e instanceof Error ? e.message : 'Sync failed',
      }));
    }
  }, [isAuthenticated, isOnline, loadCredentials]);

  // ── Step 1: Verify National ID → send OTP ────────────────────────────────
  const verifyNationalId = useCallback(async (id: string) => {
    const nid = id.trim().toUpperCase();
    try {
      const res = await holderRequestOTP(nid);
      setPendingNid(nid);
      setPendingAccountExists(res.account_exists ?? false);
      setPendingCitizen({
        nationalId: nid, fullName: '', phone: res.masked_phone,
        maskedPhone: res.masked_phone, gender: '', dob: '', region: '', city: '',
        nationality: 'Ethiopian', did: `did:et:citizen:${nid}`,
      });
      if (res.otp_for_testing) setPendingOtpForTesting(res.otp_for_testing);
      return { success: true, expiresIn: 300, maskedPhone: res.masked_phone };
    } catch (error) {
      const isOffline = error instanceof Error && (
        error.message.includes('Connection failed') ||
        error.message.includes('Network request failed') ||
        error.name === 'ConnectionError'
      );
      if (isOffline) {
        const mockCitizen = MOCK_CITIZENS[nid];
        const masked = mockCitizen
          ? mockCitizen.phone.slice(0, 3) + '****' + mockCitizen.phone.slice(-2)
          : '+251******78';
        const phone = mockCitizen ? mockCitizen.phone : '+251912345678';
        setPendingNid(nid);
        setPendingAccountExists(false);
        setPendingCitizen({
          nationalId: nid,
          fullName: mockCitizen?.fullName ?? 'Offline Citizen',
          phone, maskedPhone: masked,
          gender: mockCitizen?.gender ?? 'Male',
          dob: mockCitizen?.dob ?? '1995-01-01',
          region: mockCitizen?.region ?? 'Addis Ababa',
          city: mockCitizen?.city ?? 'Addis Ababa',
          nationality: 'Ethiopian',
          did: `did:et:citizen:${nid}`,
          photo: mockCitizen?.photo,
        });
        return { success: true, expiresIn: 300, maskedPhone: masked };
      }
      throw error;
    }
  }, []);

  const verifyOtp = useCallback(async (otp: string, phone?: string) => {
    setPendingOtp(otp);
    await AsyncStorage.setItem('pendingOtp', otp);
    if (phone) setPendingPhone(phone);
    try {
      const profileRes = await nidApi.getProfile(pendingNationalId);
      const rawObj = (profileRes && 'data' in profileRes) ? (profileRes as any).data : profileRes;
      const p = rawObj || {};
      const identityObj = p.identity || {};
      const pName    = p.full_name ?? p.fullName ?? identityObj.full_name ?? identityObj.fullName ?? '';
      const pPhone   = p.phone ?? p.phone_number ?? phone ?? '';
      const pGender  = p.gender ?? identityObj.gender ?? '';
      const pDob     = p.dob ?? identityObj.dob ?? '';
      const pAddress = p.address ?? identityObj.address ?? '';
      const pPhoto   = p.photo ?? identityObj.photo;
      const pFin     = p.fin ?? p.national_id ?? pendingNationalId;
      const pNationality = p.nationality ?? 'Ethiopian';
      const masked   = pPhone ? (pPhone.slice(0, 3) + '****' + pPhone.slice(-2)) : '****';
      setPendingCitizen({
        nationalId: pFin, fullName: pName, phone: pPhone, maskedPhone: masked,
        gender: pGender, dob: pDob,
        region: pAddress ? pAddress.split(',')[0]?.trim() : 'Addis Ababa',
        city: pAddress ? (pAddress.split(',')[1] ?? pAddress).trim() : 'Addis Ababa',
        nationality: pNationality, did: `did:et:citizen:${pFin}`, photo: pPhoto,
      });
    } catch { /* Profile fetch failed — minimal info */ }
  }, [pendingNationalId]);

  // ── Step 3: Confirm PIN → register with backend ───────────────────────────
  const confirmPinAndSetup = useCallback(async (confirmPin: string): Promise<boolean> => {
    if (confirmPin !== pendingPin) throw new Error('PIN confirmation does not match');
    const otp = pendingOtp || (await AsyncStorage.getItem('pendingOtp')) || '';
    const data = await registerWithServer(pendingNationalId, otp, pendingPhone);
    setUser(data.user as HolderUser);
    setDid(data.did);
    await setupLocalAuthentication(confirmPin);
    await AsyncStorage.removeItem('pendingOtp');
    setIsOnboarded(true);
    setIsAuthenticated(true);
    void loadCredentials();
    return true;
  }, [pendingPin, pendingOtp, pendingNationalId, pendingPhone, loadCredentials]);

  // ── Unlock ────────────────────────────────────────────────────────────────
  const unlockWithPin = useCallback(async (pin: string) => {
    const ok = await authenticateLocally(pin, false);
    if (ok) {
      setIsAuthenticated(true);
      const [u, d] = await Promise.all([getStoredUser(), getStoredDID()]);
      if (u) setUser(u as HolderUser);
      if (d) setDid(d);
      void loadCredentials();
    }
    return ok;
  }, [loadCredentials]);

  const unlockWithBiometric = useCallback(async () => {
    const ok = await authenticateLocally(undefined, true);
    if (ok) {
      setIsAuthenticated(true);
      const [u, d] = await Promise.all([getStoredUser(), getStoredDID()]);
      if (u) setUser(u as HolderUser);
      if (d) setDid(d);
      void loadCredentials();
    }
    return ok;
  }, [loadCredentials]);

  // ── Session ───────────────────────────────────────────────────────────────
  const logout = useCallback(async () => {
    await holderLogout();
    setIsAuthenticated(false);
    setRawCredentials([]); setRawActivities([]);
  }, []);

  const deleteWallet = useCallback(async () => {
    await resetAllData();
    setIsAuthenticated(false); setIsOnboarded(false);
    setUser(null); setDid(null);
    setRawCredentials([]); setRawActivities([]);
  }, []);

  // ── Prefs ─────────────────────────────────────────────────────────────────
  const setLanguage = useCallback(async (lang: string) => {
    setLangState(lang); await AsyncStorage.setItem('language', lang);
  }, []);

  const setTheme = useCallback(async (t: 'light'|'dark'|'system') => {
    setThemeState(t); await AsyncStorage.setItem('theme', t);
  }, []);

  const setupBiometric = useCallback(async () => {
    await AsyncStorage.setItem('biometricEnabled', 'true');
    setBioEnabled(true); return true;
  }, []);

  const disableBiometric = useCallback(async () => {
    await LocalAuth.disableBiometric();
    await AsyncStorage.setItem('biometricEnabled', 'false');
    setBioEnabled(false);
  }, []);

  const changePin = useCallback(async (oldPin: string, newPin: string) => {
    await LocalAuth.changePIN(oldPin, newPin);
  }, []);

  const addActivity = useCallback((a: Omit<Activity, 'id'>) => {
    setRawActivities(prev => [{ ...a, id: `act-${Date.now()}` } as Activity, ...prev]);
  }, []);

  const value = useMemo<AuthContextType>(() => ({
    isLoading, isOnboarded, isAuthenticated,
    biometricEnabled, biometricAvailable,
    user, citizen, did,
    credentials, activities,
    isLoadingCredentials: isLoadingCreds,
    isLoadingActivities: isLoadingActs,
    language, theme, pendingNationalId, pendingCitizen,
    pendingAccountExists, pendingPhone, pendingOtpForTesting, setPendingPhone,
    isOnline, syncStatus,
    verifyNationalId, verifyOtp,
    setPendingPin: setPendingPinState,
    confirmPinAndSetup, unlockWithPin, unlockWithBiometric,
    logout, deleteWallet, setLanguage, setTheme,
    setupBiometric, disableBiometric, changePin,
    refreshCredentials: loadCredentials,
    refreshActivities: loadActivities,
    addActivity, syncNow,
  }), [
    isLoading, isOnboarded, isAuthenticated, biometricEnabled, biometricAvailable,
    user, citizen, did, credentials, activities, isLoadingCreds, isLoadingActs,
    language, theme, pendingNationalId, pendingCitizen,
    pendingAccountExists, pendingPhone, pendingOtpForTesting,
    isOnline, syncStatus,
    verifyNationalId, verifyOtp, confirmPinAndSetup,
    unlockWithPin, unlockWithBiometric, logout, deleteWallet,
    setLanguage, setTheme, setupBiometric, disableBiometric, changePin,
    loadCredentials, loadActivities, addActivity, syncNow,
  ]);

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth(): AuthContextType {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
}

