    11→const NOTIF_KEY = 'wallet_notifications';
    12→const POLL_INTERVAL_MS = 60 * 1000;
    13→
    14→export interface WalletNotification {
    15→  id: string;
    16→  title: string;
    17→  message: string;
    18→  type: string;
    19→  is_read: boolean;
    20→  created_at: string;
    21→  data?: Record<string, unknown>;
    22→}
    23→
    24→type Listener = (notifications: WalletNotification[]) => void;
    25→
    26→let pollTimer: ReturnType<typeof setInterval> | null = null;
    27→let appStateSubscription: ReturnType<typeof AppState.addEventListener> | null = null;
    28→let listeners: Listener[] = [];
    29→let cachedNotifications: WalletNotification[] = [];
    30→
    31→const getClient = () => new ApiClient(getApiConfig());
    32→
    33→export async function fetchNotifications(): Promise<WalletNotification[]> {
    34→  try {
    35→    const token = await getAccessToken();
    36→    if (!token) return getCachedNotifications();
    37→
    38→    const client = getClient();
    39→    const res = await client.get<unknown>('/wallet/notifications/', token);
    40→    let notifications: WalletNotification[] = [];
    41→
    42→    if (Array.isArray(res)) {
    43→      notifications = res as WalletNotification[];
    44→    } else if (res && typeof res === 'object' && 'results' in (res as object)) {
    45→      notifications = (res as Record<string, unknown>).results as WalletNotification[];
    46→    }
    47→
    48→    await AsyncStorage.setItem(NOTIF_KEY, JSON.stringify(notifications));
    49→    cachedNotifications = notifications;
    50→    listeners.forEach(l => l(notifications));
    51→    return notifications;
    52→  } catch {
    53→    return getCachedNotifications();
    54→  }
    55→}
