    11→};
    12→
    13→const useNotifications = () => {
    14→  const { role, isAuthenticated } = useAuthStore();
    15→
    16→  const fetchCount = useCallback(async () => {
    17→    if (!isAuthenticated || !role || role === 'admin') return;
    18→    try {
    19→      const res = await getUnreadCount(role);
    20→      const storeModule = await stores[role]?.();
    21→      if (storeModule) storeModule.getState().setUnreadCount(res.data?.count || 0);
    22→    } catch { /* ignore */ }
    23→  }, [role, isAuthenticated]);
    24→
    25→  const fetchNotifications = useCallback(async (params) => {
    26→    if (!isAuthenticated || !role) return [];
    27→    try {
    28→      let res;
    29→      if (role === 'admin') {
    30→        const { getAdminNotifications } = await import('../api/admin');
    31→        res = await getAdminNotifications(params);
    32→      } else {
    33→        res = await getNotifications(role, params);
    34→      }
    35→      const storeModule = await stores[role]?.();
    36→      const data = res.data?.results || res.data || [];
    37→      if (storeModule) storeModule.getState().setNotifications(data);
    38→      return data;
    39→    } catch { return []; }
    40→  }, [role, isAuthenticated]);
    41→
    42→  useEffect(() => {
    43→    fetchCount();
    44→    const t = setInterval(fetchCount, NOTIFICATION_POLL_INTERVAL);
    45→    return () => clearInterval(t);
    46→  }, [fetchCount]);
    47→
    48→  return { fetchCount, fetchNotifications, markRead: (id) => markRead(role, id), markAllRead: () => markAllRead(role), deleteNotification: (id) => deleteNotification(role, id) };
    49→};
